export default Sidebar;

import React from 'react';

interface KPICardProps {
  title: string;
  value: string | number;
  unit?: string;
  icon: string;
  trend?: {
    value: number;
    isUp: boolean;
  };
  color: 'emerald' | 'blue' | 'amber' | 'rose' | 'indigo';
}

const KPICard: React.FC<KPICardProps> = ({ title, value, unit, icon, trend, color }) => {
  const colorMap = {
    emerald: 'bg-emerald-50 text-emerald-600 border-emerald-100',
    blue: 'bg-blue-50 text-blue-600 border-blue-100',
    amber: 'bg-amber-50 text-amber-600 border-amber-100',
    rose: 'bg-rose-50 text-rose-600 border-rose-100',
    indigo: 'bg-indigo-50 text-indigo-600 border-indigo-100',
  };

  const iconColorMap = {
    emerald: 'bg-emerald-500',
    blue: 'bg-blue-500',
    amber: 'bg-amber-500',
    rose: 'bg-rose-500',
    indigo: 'bg-indigo-500',
  };

  return (
    <div className={`bg-white rounded-2xl p-6 border shadow-sm transition-transform hover:scale-[1.02] cursor-default`}>
      <div className="flex items-start justify-between mb-4">
        <div className={`p-3 rounded-xl text-white shadow-lg ${iconColorMap[color]}`}>
          <i className={`fa-solid ${icon} text-lg`}></i>
        </div>
        {trend && (
          <span className={`text-xs font-bold flex items-center gap-1 ${trend.isUp ? 'text-rose-500' : 'text-emerald-500'}`}>
            <i className={`fa-solid ${trend.isUp ? 'fa-arrow-trend-up' : 'fa-arrow-trend-down'}`}></i>
            {Math.abs(trend.value)}%
          </span>
        )}
      </div>
      <p className="text-slate-500 text-sm font-medium">{title}</p>
      <div className="flex items-baseline gap-1 mt-1">
        <h3 className="text-2xl font-bold text-slate-900">{value}</h3>
        {unit && <span className="text-slate-400 text-sm font-medium">{unit}</span>}
      </div>
    </div>
  );
};

export default KPICard;

import React, { useMemo } from 'react';
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, AreaChart, Area, Cell, PieChart, Pie } from 'recharts';
import { Supplier, Material, ProcurementRecord, EnergyRecord } from '../types';
import KPICard from '../components/KPICard';

interface DashboardProps {
  suppliers: Supplier[];
  materials: Material[];
  procurement: ProcurementRecord[];
  energy: EnergyRecord[];
}

const Dashboard: React.FC<DashboardProps> = ({ suppliers, materials, procurement, energy }) => {

  const stats = useMemo(() => {
    // Total Carbon Emissions
    const energyCarbon = energy.reduce((sum, e) => sum + e.carbonEquivalent, 0);
    const materialCarbon = procurement.reduce((sum, p) => {
      const mat = materials.find(m => m.id === p.materialId);
      return sum + (p.quantity * (mat?.carbonFactor || 0));
    }, 0);

    const totalCarbon = energyCarbon + materialCarbon;

    // Average Supplier Score
    const avgSupplierScore = suppliers.length > 0 
      ? Math.round(suppliers.reduce((sum, s) => sum + s.sustainabilityScore, 0) / suppliers.length)
      : 0;

    // Total Spend
    const totalSpend = procurement.reduce((sum, p) => sum + p.totalCost, 0);

    // Recyclability Average
    const weightedRecyclability = procurement.reduce((sum, p) => {
      const mat = materials.find(m => m.id === p.materialId);
      return sum + (p.quantity * (mat?.recyclabilityRate || 0));
    }, 0);
    const totalQty = procurement.reduce((sum, p) => sum + p.quantity, 0);
    const avgRecyclability = totalQty > 0 ? Math.round(weightedRecyclability / totalQty) : 0;

    return {
      totalCarbon,
      avgSupplierScore,
      totalSpend,
      avgRecyclability,
      energyCarbon,
      materialCarbon
    };
  }, [suppliers, materials, procurement, energy]);

  const emissionBySourceData = [
    { name: 'Energy Consumption', value: stats.energyCarbon, color: '#10b981' },
    { name: 'Material Procurement', value: stats.materialCarbon, color: '#3b82f6' },
  ];

  // Group by month for trend
  const trendData = [
    { month: 'Jul', co2: 2400 },
    { month: 'Aug', co2: 2100 },
    { month: 'Sep', co2: 2800 },
    { month: 'Oct', co2: stats.totalCarbon > 0 ? Math.round(stats.totalCarbon) : 2500 },
  ];

  const topMaterialsData = materials
    .map(m => ({
      name: m.name,
      impact: m.carbonFactor,
    }))
    .sort((a, b) => b.impact - a.impact)
    .slice(0, 4);

  return (
    <div className="space-y-8 animate-in fade-in duration-500">
      <header className="flex justify-between items-center">
        <div>
          <h2 className="text-3xl font-bold text-slate-900 tracking-tight">Sustainability Overview</h2>
          <p className="text-slate-500 mt-1">Real-time environmental and procurement analytics.</p>
        </div>
        <div className="flex gap-2">
          <button className="bg-white px-4 py-2 text-sm font-semibold border rounded-lg hover:bg-slate-50 transition-colors shadow-sm">
            <i className="fa-solid fa-calendar-days mr-2 text-slate-400"></i> Last 30 Days
          </button>
          <button className="bg-emerald-600 text-white px-4 py-2 text-sm font-semibold rounded-lg hover:bg-emerald-700 transition-colors shadow-md">
            <i className="fa-solid fa-download mr-2"></i> Export Data
          </button>
        </div>
      </header>

      {/* KPI Grid */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
        <KPICard 
          title="Total Carbon Footprint" 
          value={stats.totalCarbon.toLocaleString()} 
          unit="kg CO2e" 
          icon="fa-cloud" 
          color="rose"
          trend={{ value: 4.2, isUp: false }}
        />
        <KPICard 
          title="Avg. Supplier Score" 
          value={stats.avgSupplierScore} 
          unit="/ 100" 
          icon="fa-award" 
          color="emerald"
        />
        <KPICard 
          title="Total Material Spend" 
          value={`$${(stats.totalSpend / 1000).toFixed(1)}k`} 
          icon="fa-wallet" 
          color="indigo"
          trend={{ value: 1.8, isUp: true }}
        />
        <KPICard 
          title="Material Recyclability" 
          value={stats.avgRecyclability} 
          unit="%" 
          icon="fa-recycle" 
          color="amber"
        />
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
        {/* Emission Trend */}
        <div className="lg:col-span-2 bg-white p-6 rounded-2xl border shadow-sm">
          <div className="flex items-center justify-between mb-6">
            <h3 className="text-lg font-bold text-slate-800">Carbon Emission Trend</h3>
            <div className="flex items-center gap-2">
              <span className="flex items-center gap-1 text-xs text-slate-500">
                <span className="w-2 h-2 rounded-full bg-emerald-500"></span> Current
              </span>
            </div>
          </div>
          <div className="h-[300px]">
            <ResponsiveContainer width="100%" height="100%">
              <AreaChart data={trendData}>
                <defs>
                  <linearGradient id="colorCo2" x1="0" y1="0" x2="0" y2="1">
                    <stop offset="5%" stopColor="#10b981" stopOpacity={0.1}/>
                    <stop offset="95%" stopColor="#10b981" stopOpacity={0}/>
                  </linearGradient>
                </defs>
                <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f1f5f9" />
                <XAxis dataKey="month" axisLine={false} tickLine={false} tick={{fill: '#64748b', fontSize: 12}} />
                <YAxis axisLine={false} tickLine={false} tick={{fill: '#64748b', fontSize: 12}} />
                <Tooltip 
                  contentStyle={{ borderRadius: '12px', border: 'none', boxShadow: '0 10px 15px -3px rgb(0 0 0 / 0.1)' }}
                  itemStyle={{ fontWeight: 600 }}
                />
                <Area type="monotone" dataKey="co2" stroke="#10b981" strokeWidth={3} fillOpacity={1} fill="url(#colorCo2)" />
              </AreaChart>
            </ResponsiveContainer>
          </div>
        </div>

        {/* Breakdown */}
        <div className="bg-white p-6 rounded-2xl border shadow-sm">
          <h3 className="text-lg font-bold text-slate-800 mb-6 text-center">Emission Source Breakdown</h3>
          <div className="h-[250px] relative">
            <ResponsiveContainer width="100%" height="100%">
              <PieChart>
                <Pie
                  data={emissionBySourceData}
                  cx="50%"
                  cy="50%"
                  innerRadius={60}
                  outerRadius={80}
                  paddingAngle={8}
                  dataKey="value"
                >
                  {emissionBySourceData.map((entry, index) => (
                    <Cell key={`cell-${index}`} fill={entry.color} />
                  ))}
                </Pie>
                <Tooltip />
              </PieChart>
            </ResponsiveContainer>
            <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 text-center pointer-events-none">
                <p className="text-xs text-slate-400 font-medium">TOTAL</p>
                <p className="text-xl font-bold text-slate-800">{Math.round(stats.totalCarbon / 1000)}t</p>
            </div>
          </div>
          <div className="space-y-3 mt-4">
            {emissionBySourceData.map((source, i) => (
              <div key={i} className="flex items-center justify-between">
                <div className="flex items-center gap-2">
                  <div className="w-3 h-3 rounded-full" style={{ backgroundColor: source.color }}></div>
                  <span className="text-xs font-medium text-slate-600">{source.name}</span>
                </div>
                <span className="text-xs font-bold text-slate-900">{Math.round((source.value / stats.totalCarbon) * 100)}%</span>
              </div>
            ))}
          </div>
        </div>
      </div>

      {/* Material Impact Table */}
      <div className="bg-white rounded-2xl border shadow-sm overflow-hidden">
        <div className="px-6 py-4 border-b flex items-center justify-between">
          <h3 className="text-lg font-bold text-slate-800">High-Impact Materials</h3>
          <button className="text-emerald-600 text-sm font-semibold hover:underline">View All</button>
        </div>
        <div className="overflow-x-auto">
          <table className="w-full text-left">
            <thead className="bg-slate-50 text-slate-500 text-xs uppercase tracking-wider">
              <tr>
                <th className="px-6 py-4 font-semibold">Material</th>
                <th className="px-6 py-4 font-semibold text-center">Impact Score</th>
                <th className="px-6 py-4 font-semibold text-center">Recyclability</th>
                <th className="px-6 py-4 font-semibold text-center">Status</th>
              </tr>
            </thead>
            <tbody className="divide-y text-sm">
              {materials.slice(0, 5).map((mat) => (
                <tr key={mat.id} className="hover:bg-slate-50 transition-colors">
                  <td className="px-6 py-4">
                    <div className="font-semibold text-slate-900">{mat.name}</div>
                    <div className="text-slate-400 text-xs">{mat.category}</div>
                  </td>
                  <td className="px-6 py-4">
                    <div className="w-full bg-slate-100 rounded-full h-2 max-w-[100px] mx-auto overflow-hidden">
                      <div 
                        className={`h-full rounded-full ${mat.carbonFactor > 10 ? 'bg-rose-500' : mat.carbonFactor > 5 ? 'bg-amber-500' : 'bg-emerald-500'}`} 
                        style={{ width: `${Math.min(100, (mat.carbonFactor / 15) * 100)}%` }}
                      ></div>
                    </div>
                  </td>
                  <td className="px-6 py-4 text-center">
                    <span className="font-medium text-slate-700">{mat.recyclabilityRate}%</span>
                  </td>
                  <td className="px-6 py-4 text-center">
                    <span className={`px-2 py-1 rounded-full text-[10px] font-bold uppercase ${mat.carbonFactor > 10 ? 'bg-rose-100 text-rose-600' : 'bg-emerald-100 text-emerald-600'}`}>
                        {mat.carbonFactor > 10 ? 'Critical' : 'Sustainable'}
                    </span>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
};

export default Dashboard;

import React, { useMemo } from 'react';
import { Supplier, Material, ProcurementRecord, Recommendation } from '../types';

interface RecommendationEngineProps {
  suppliers: Supplier[];
  materials: Material[];
  procurement: ProcurementRecord[];
}

const RecommendationEngine: React.FC<RecommendationEngineProps> = ({ suppliers, materials, procurement }) => {

  const recommendations = useMemo(() => {
    const recs: Recommendation[] = [];

    // Rule 1: High CO2 Material Alert
    const highImpactMaterials = materials.filter(m => m.carbonFactor > 10);
    highImpactMaterials.forEach(m => {
      const alternative = materials.find(alt => alt.category === m.category && alt.carbonFactor < m.carbonFactor);
      if (alternative) {
        recs.push({
          id: `rec-m-${m.id}`,
          type: 'MATERIAL',
          title: `Switch Material: ${m.name}`,
          description: `Consider replacing '${m.name}' with '${alternative.name}' which has ${Math.round((1 - alternative.carbonFactor/m.carbonFactor) * 100)}% lower carbon footprint.`,
          impact: 'High'
        });
      }
    });

    // Rule 2: Low Supplier Score Warning
    const activeSupplierIds = new Set(procurement.map(p => p.supplierId));
    suppliers.filter(s => activeSupplierIds.has(s.id) && s.sustainabilityScore < 60).forEach(s => {
      const betterSupplier = suppliers.find(alt => alt.category === s.category && alt.sustainabilityScore > 80);
      if (betterSupplier) {
        recs.push({
          id: `rec-s-${s.id}`,
          type: 'SUPPLIER',
          title: `Upgrade Supplier: ${s.name}`,
          description: `Switching to '${betterSupplier.name}' (Score: ${betterSupplier.sustainabilityScore}) could significantly improve your overall sustainability rating.`,
          impact: 'Medium'
        });
      }
    });

    // Rule 3: Consolidation/Optimization
    const frequentPurchases = procurement.length > 5;
    if (frequentPurchases) {
      recs.push({
        id: 'rec-opt-1',
        type: 'OPTIMIZATION',
        title: 'Bulk Order Consolidation',
        description: 'Reduce transport emissions by consolidating multiple small orders from the same supplier into monthly bulk shipments.',
        impact: 'Low'
      });
    }

    return recs;
  }, [suppliers, materials, procurement]);

  return (
    <div className="space-y-6 animate-in slide-in-from-bottom duration-500">
      <header>
        <h2 className="text-3xl font-bold text-slate-900 tracking-tight">Smart Recommendations</h2>
        <p className="text-slate-500 mt-1">Rule-based insights to drive sustainable procurement decisions.</p>
      </header>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
        {recommendations.length > 0 ? (
          recommendations.map(rec => (
            <div key={rec.id} className="bg-white rounded-2xl border p-6 shadow-sm hover:shadow-md transition-all flex flex-col relative overflow-hidden group">
              <div className={`absolute top-0 right-0 w-32 h-32 -mr-16 -mt-16 rounded-full opacity-5 group-hover:opacity-10 transition-opacity ${
                rec.type === 'MATERIAL' ? 'bg-rose-500' : rec.type === 'SUPPLIER' ? 'bg-emerald-500' : 'bg-blue-500'
              }`}></div>

              <div className="flex items-center justify-between mb-4">
                <div className={`w-10 h-10 rounded-xl flex items-center justify-center text-white shadow-lg ${
                  rec.type === 'MATERIAL' ? 'bg-rose-500' : rec.type === 'SUPPLIER' ? 'bg-emerald-500' : 'bg-blue-500'
                }`}>
                  <i className={`fa-solid ${rec.type === 'MATERIAL' ? 'fa-box-open' : rec.type === 'SUPPLIER' ? 'fa-handshake' : 'fa-arrows-to-circle'}`}></i>
                </div>
                <span className={`px-2 py-0.5 rounded-full text-[10px] font-bold uppercase ${
                  rec.impact === 'High' ? 'bg-rose-100 text-rose-600 border border-rose-200' : 
                  rec.impact === 'Medium' ? 'bg-amber-100 text-amber-600 border border-amber-200' : 
                  'bg-blue-100 text-blue-600 border border-blue-200'
                }`}>
                  {rec.impact} Impact
                </span>
              </div>

              <h3 className="text-lg font-bold text-slate-900 mb-2">{rec.title}</h3>
              <p className="text-slate-500 text-sm leading-relaxed flex-1">{rec.description}</p>

              <div className="mt-6 pt-6 border-t border-slate-50 flex items-center justify-between">
                <button className="text-emerald-600 text-xs font-bold uppercase tracking-wider hover:text-emerald-700 transition-colors flex items-center gap-2">
                  Apply Strategy <i className="fa-solid fa-arrow-right"></i>
                </button>
