import React, { useState } from 'react';
import { Material, Supplier, ProcurementRecord, EnergyRecord } from '../types';

interface DataManagementProps {
  materials: Material[];
  suppliers: Supplier[];
  onAddProcurement: (p: Omit<ProcurementRecord, 'id'>) => void;
  onAddEnergy: (e: Omit<EnergyRecord, 'id'>) => void;
}

const DataManagement: React.FC<DataManagementProps> = ({ materials, suppliers, onAddProcurement, onAddEnergy }) => {
  const [tab, setTab] = useState<'procurement' | 'energy'>('procurement');

  const [pFormData, setPFormData] = useState({
    date: new Date().toISOString().split('T')[0],
    materialId: '',
    supplierId: '',
    quantity: 0,
    totalCost: 0
  });

  const [eFormData, setEFormData] = useState({
    date: new Date().toISOString().split('T')[0],
    source: 'Electricity' as EnergyRecord['source'],
    amount: 0,
    unit: 'kWh',
    carbonEquivalent: 0
  });

  const handlePSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!pFormData.materialId || !pFormData.supplierId || pFormData.quantity <= 0) return;
    onAddProcurement(pFormData);
    alert('Procurement record added successfully!');
  };

  const handleESubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (eFormData.amount <= 0) return;
    // Simple mock calculation: Electricity 0.4kg/kWh, Diesel 2.6kg/L
    const factors = { 'Electricity': 0.41, 'Natural Gas': 0.2, 'Solar': 0, 'Diesel': 2.68 };
    const carbon = eFormData.amount * (factors[eFormData.source] || 0);
    onAddEnergy({ ...eFormData, carbonEquivalent: carbon });
    alert('Energy record added successfully!');
  };

  return (
    <div className="space-y-6 animate-in fade-in duration-500">
      <header>
        <h2 className="text-3xl font-bold text-slate-900 tracking-tight">Data Entry</h2>
        <p className="text-slate-500 mt-1">Upload and manage operational data for KPI calculation.</p>
      </header>

      <div className="max-w-2xl mx-auto bg-white rounded-2xl border shadow-xl overflow-hidden">
        <div className="flex bg-slate-50 border-b">
          <button 
            onClick={() => setTab('procurement')}
            className={`flex-1 py-5 text-sm font-bold transition-all border-r ${tab === 'procurement' ? 'bg-white text-emerald-600 border-b-emerald-600' : 'text-slate-400 hover:text-slate-600'}`}
          >
            <i className="fa-solid fa-cart-shopping mr-2"></i>
            Procurement Log
          </button>
          <button 
            onClick={() => setTab('energy')}
            className={`flex-1 py-5 text-sm font-bold transition-all ${tab === 'energy' ? 'bg-white text-amber-600 border-b-amber-600' : 'text-slate-400 hover:text-slate-600'}`}
          >
            <i className="fa-solid fa-bolt mr-2"></i>
            Energy Usage
          </button>
        </div>

        <div className="p-8">
          {tab === 'procurement' ? (
            <form onSubmit={handlePSubmit} className="space-y-4">
              <div className="grid grid-cols-2 gap-4">
                <div className="space-y-1">
                  <label className="text-xs font-bold text-slate-500 uppercase tracking-wider">Date</label>
                  <input 
                    type="date" 
                    className="w-full border p-3 rounded-xl focus:ring-2 focus:ring-emerald-500 outline-none" 
                    value={pFormData.date}
                    onChange={e => setPFormData({...pFormData, date: e.target.value})}
                  />
                </div>
                <div className="space-y-1">
                  <label className="text-xs font-bold text-slate-500 uppercase tracking-wider">Quantity</label>
                  <input 
                    type="number" 
                    placeholder="e.g. 500" 
                    className="w-full border p-3 rounded-xl focus:ring-2 focus:ring-emerald-500 outline-none" 
                    value={pFormData.quantity || ''}
                    onChange={e => setPFormData({...pFormData, quantity: Number(e.target.value)})}
                  />
                </div>
              </div>

              <div className="space-y-1">
                <label className="text-xs font-bold text-slate-500 uppercase tracking-wider">Material</label>
                <select 
                  className="w-full border p-3 rounded-xl focus:ring-2 focus:ring-emerald-500 outline-none appearance-none"
                  value={pFormData.materialId}
                  onChange={e => setPFormData({...pFormData, materialId: e.target.value})}
                >
                  <option value="">Select Material...</option>
                  {materials.map(m => <option key={m.id} value={m.id}>{m.name} ({m.unit})</option>)}
                </select>
              </div>

              <div className="space-y-1">
                <label className="text-xs font-bold text-slate-500 uppercase tracking-wider">Supplier</label>
                <select 
                  className="w-full border p-3 rounded-xl focus:ring-2 focus:ring-emerald-500 outline-none appearance-none"
                  value={pFormData.supplierId}
                  onChange={e => setPFormData({...pFormData, supplierId: e.target.value})}
                >
                  <option value="">Select Supplier...</option>
                  {suppliers.map(s => <option key={s.id} value={s.id}>{s.name} - Score: {s.sustainabilityScore}</option>)}
                </select>
              </div>

              <div className="space-y-1">
                <label className="text-xs font-bold text-slate-500 uppercase tracking-wider">Total Cost ($)</label>
                <input 
                  type="number" 
                  placeholder="Total order value" 
                  className="w-full border p-3 rounded-xl focus:ring-2 focus:ring-emerald-500 outline-none" 
                  value={pFormData.totalCost || ''}
