                <div className="space-y-1">
                  <label className="text-xs font-bold text-slate-500 uppercase tracking-wider">Consumption Amount</label>
                  <input 
                    type="number" 
                    placeholder="Value" 
                    className="w-full border p-3 rounded-xl focus:ring-2 focus:ring-amber-500 outline-none" 
                    value={eFormData.amount || ''}
                    onChange={e => setEFormData({...eFormData, amount: Number(e.target.value)})}
                  />
                </div>
              </div>

              <div className="space-y-1">
                <label className="text-xs font-bold text-slate-500 uppercase tracking-wider">Energy Source</label>
                <select 
                  className="w-full border p-3 rounded-xl focus:ring-2 focus:ring-amber-500 outline-none appearance-none"
                  value={eFormData.source}
                  onChange={e => setEFormData({...eFormData, source: e.target.value as EnergyRecord['source']})}
                >
                  <option value="Electricity">Electricity (Grid)</option>
                  <option value="Solar">Solar (On-site)</option>
                  <option value="Natural Gas">Natural Gas</option>
                  <option value="Diesel">Diesel / Generator</option>
                </select>
              </div>

              <div className="p-4 bg-amber-50 rounded-xl border border-amber-100 mt-6 text-sm text-amber-800">
                <div className="flex items-center gap-2 font-bold mb-1">
                  <i className="fa-solid fa-calculator"></i> Carbon Estimator
                </div>
                <p>Estimated CO2 impact: <strong>{Math.round(eFormData.amount * (eFormData.source === 'Electricity' ? 0.41 : eFormData.source === 'Diesel' ? 2.68 : 0))} kg CO2e</strong></p>
              </div>

              <button type="submit" className="w-full bg-amber-600 text-white py-4 rounded-xl font-bold text-lg hover:bg-amber-700 transition-all shadow-lg hover:shadow-amber-200/50 mt-4">
                Log Energy Usage
