import React, { useState, useMemo } from 'react';
import { UserRole, User, Supplier, Material, ProcurementRecord, EnergyRecord } from './types';
import { INITIAL_USERS, INITIAL_SUPPLIERS, INITIAL_MATERIALS, INITIAL_PROCUREMENT, INITIAL_ENERGY } from './constants';
import Sidebar from './components/Sidebar';
import Dashboard from './views/Dashboard';
import MasterData from './views/MasterData';
import DataManagement from './views/DataManagement';
import RecommendationEngine from './views/RecommendationEngine';

const App: React.FC = () => {
  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [activeTab, setActiveTab] = useState('dashboard');
  const [isGeneratingReport, setIsGeneratingReport] = useState(false);

  // App State
  const [suppliers, setSuppliers] = useState<Supplier[]>(INITIAL_SUPPLIERS);
  const [materials, setMaterials] = useState<Material[]>(INITIAL_MATERIALS);
  const [procurement, setProcurement] = useState<ProcurementRecord[]>(INITIAL_PROCUREMENT);
  const [energy, setEnergy] = useState<EnergyRecord[]>(INITIAL_ENERGY);
  const [users, setUsers] = useState<User[]>(INITIAL_USERS);

  // Auth logic
  const [loginInput, setLoginInput] = useState({ username: '', role: UserRole.ADMIN });

  const handleLogin = (e: React.FormEvent) => {
    e.preventDefault();
    const user = users.find(u => u.username.toLowerCase() === loginInput.username.toLowerCase() && u.role === loginInput.role);
    if (user) {
      setCurrentUser(user);
    } else {
      alert('Invalid user credentials. For this prototype, try username "admin" with ADMIN role.');
    }
  };

  const handleLogout = () => {
    setCurrentUser(null);
    setActiveTab('dashboard');
  };

  // Data Handlers
  const addProcurement = (p: Omit<ProcurementRecord, 'id'>) => {
    setProcurement(prev => [{ ...p, id: `p-${Date.now()}` }, ...prev]);
  };

  const addEnergy = (e: Omit<EnergyRecord, 'id'>) => {
    setEnergy(prev => [{ ...e, id: `e-${Date.now()}` }, ...prev]);
  };

  const manageSupplier = (supplier: Supplier, mode: 'add' | 'edit' | 'delete') => {
    if (mode === 'add') setSuppliers(prev => [...prev, supplier]);
    if (mode === 'edit') setSuppliers(prev => prev.map(s => s.id === supplier.id ? supplier : s));
    if (mode === 'delete') setSuppliers(prev => prev.filter(s => s.id !== supplier.id));
  };

  const manageMaterial = (material: Material, mode: 'add' | 'edit' | 'delete') => {
    if (mode === 'add') setMaterials(prev => [...prev, material]);
    if (mode === 'edit') setMaterials(prev => prev.map(m => m.id === material.id ? material : m));
    if (mode === 'delete') setMaterials(prev => prev.filter(m => m.id !== material.id));
  };

  const manageUser = (user: User, mode: 'add' | 'delete') => {
    if (mode === 'add') setUsers(prev => [...prev, user]);
    if (mode === 'delete') {
      if (user.id === currentUser?.id) return alert("Cannot delete currently logged-in user.");
      setUsers(prev => prev.filter(u => u.id !== user.id));
    }
  };

  const handleGenerateReport = () => {
    setIsGeneratingReport(true);
    setTimeout(() => {
      const energyCarbon = energy.reduce((sum, e) => sum + e.carbonEquivalent, 0);
      const materialCarbon = procurement.reduce((sum, p) => {
        const mat = materials.find(m => m.id === p.materialId);
        return sum + (p.quantity * (mat?.carbonFactor || 0));
      }, 0);

      const reportData = [
        ["Annual Sustainability Report", "2023"],
        ["Generated By", currentUser?.username || "System"],
        [""],
        ["KPI SUMMARY"],
        ["Total Energy Carbon Footprint", energyCarbon + " kg CO2e"],
        ["Total Procurement Carbon Footprint", materialCarbon + " kg CO2e"],
        ["Total Cumulative Footprint", (energyCarbon + materialCarbon) + " kg CO2e"],
        [""],
        ["ENERGY CONSUMPTION DETAILS"],
        ["Source", "Date", "Amount", "CO2 Equivalent"],
        ...energy.map(e => [e.source, e.date, e.amount + " " + e.unit, e.carbonEquivalent + " kg"]),
        [""],
        ["PROCUREMENT LOGS"],
        ["Date", "Material", "Quantity", "Total Cost"],
        ...procurement.map(p => {
          const m = materials.find(mat => mat.id === p.materialId);
          return [p.date, m?.name || "Unknown", p.quantity, "$" + p.totalCost];
        })
      ];

      const csvContent = reportData.map(e => e.join(",")).join("\n");
      const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' });
      const link = document.createElement("a");
      const url = URL.createObjectURL(blob);
      link.setAttribute("href", url);
      link.setAttribute("download", `annual_sustainability_report_${new Date().getFullYear()}.csv`);
      link.style.visibility = 'hidden';
      document.body.appendChild(link);
      link.click();
      document.body.removeChild(link);

      setIsGeneratingReport(false);
      alert('Sustainability Report generated and downloaded successfully!');
    }, 1500);
  };

  if (!currentUser) {
    return (
      <div className="min-h-screen bg-slate-900 flex items-center justify-center p-4">
        <div className="bg-white w-full max-w-md rounded-3xl p-8 shadow-2xl animate-in zoom-in duration-300">
          <div className="text-center mb-8">
            <div className="w-16 h-16 bg-emerald-100 text-emerald-600 rounded-2xl flex items-center justify-center text-3xl mx-auto mb-4">
              <i className="fa-solid fa-leaf"></i>
            </div>
            <h1 className="text-3xl font-extrabold text-slate-900">Green ERP</h1>
            <p className="text-slate-500 mt-2 font-medium">Sustainability Decision Support</p>
          </div>

          <form onSubmit={handleLogin} className="space-y-6">
            <div className="space-y-2">
              <label className="text-xs font-bold text-slate-500 uppercase tracking-widest ml-1">Username</label>
              <input 
                type="text" 
                className="w-full bg-slate-50 border border-slate-100 p-4 rounded-xl focus:ring-2 focus:ring-emerald-500 outline-none transition-all font-medium" 
                placeholder="e.g. admin"
                value={loginInput.username}
                onChange={e => setLoginInput({...loginInput, username: e.target.value})}
                required
              />
            </div>

            <div className="space-y-2">
              <label className="text-xs font-bold text-slate-500 uppercase tracking-widest ml-1">Select Role</label>
              <div className="grid grid-cols-1 gap-2">
                {[UserRole.ADMIN, UserRole.PROCUREMENT_MANAGER, UserRole.SUSTAINABILITY_MANAGER].map(role => (
                  <button
                    key={role}
                    type="button"
                    onClick={() => setLoginInput({...loginInput, role})}
                    className={`text-left px-4 py-3 rounded-xl border text-sm font-semibold transition-all ${
                      loginInput.role === role 
                        ? 'border-emerald-500 bg-emerald-50 text-emerald-700' 
                        : 'border-slate-100 bg-slate-50 text-slate-400 hover:border-emerald-200'
                    }`}
                  >
                    <i className={`fa-solid ${role === UserRole.ADMIN ? 'fa-user-shield' : role === UserRole.PROCUREMENT_MANAGER ? 'fa-truck-ramp-box' : 'fa-seedling'} mr-2`}></i>
                    {role.replace('_', ' ')}
                  </button>
                ))}
              </div>
            </div>

            <button type="submit" className="w-full bg-slate-900 text-white py-4 rounded-xl font-bold text-lg hover:bg-emerald-600 transition-all shadow-xl hover:shadow-emerald-200/50 flex items-center justify-center gap-2">
              Launch Portal
              <i className="fa-solid fa-arrow-right"></i>
            </button>
          </form>

          <div className="mt-8 pt-6 border-t border-slate-100 text-center">
             <p className="text-xs text-slate-400">© 2024 Green ERP System - MCA Final Year Project</p>
          </div>
        </div>
      </div>
    );
  }

  const renderContent = () => {
    switch(activeTab) {
      case 'dashboard':
        return <Dashboard suppliers={suppliers} materials={materials} procurement={procurement} energy={energy} />;
      case 'master-data':
        return <MasterData suppliers={suppliers} materials={materials} onSupplierAction={manageSupplier} onMaterialAction={manageMaterial} />;
      case 'data-management':
        return (
          <DataManagement 
            materials={materials} 
            suppliers={suppliers} 
            procurement={procurement}
            energy={energy}
            onAddProcurement={addProcurement} 
            onAddEnergy={addEnergy} 
          />
        );
      case 'recommendations':
        return <RecommendationEngine suppliers={suppliers} materials={materials} procurement={procurement} />;
      case 'reports':
        return (
          <div className="flex flex-col items-center justify-center py-24 space-y-6">
             <div className="w-24 h-24 bg-white rounded-full flex items-center justify-center shadow-xl border border-slate-100 mb-2">
                <i className={`fa-solid ${isGeneratingReport ? 'fa-spinner animate-spin text-emerald-500' : 'fa-file-pdf text-slate-300'} text-5xl`}></i>
             </div>
             <div className="text-center">
                <h3 className="text-2xl font-bold text-slate-900">Sustainability Reporting</h3>
                <p className="text-slate-500 text-center max-w-md mt-2">Generate comprehensive GHG Protocol-aligned carbon reports and supplier performance summaries in one click.</p>
             </div>
             <button 
                onClick={handleGenerateReport}
                disabled={isGeneratingReport}
                className={`bg-emerald-600 text-white px-8 py-3 rounded-xl font-bold hover:bg-emerald-700 transition-all shadow-lg flex items-center gap-2 ${isGeneratingReport ? 'opacity-70 cursor-wait' : ''}`}
             >
               {isGeneratingReport ? 'Compiling Dataset...' : 'Generate Annual Report'}
               {!isGeneratingReport && <i className="fa-solid fa-bolt"></i>}
             </button>
          </div>
        );
      case 'users':
        return (
          <div className="bg-white p-8 rounded-2xl border shadow-sm max-w-4xl mx-auto">
             <div className="flex justify-between items-center mb-8">
                <h3 className="text-2xl font-bold text-slate-900">System Users</h3>
                <button 
                  onClick={() => manageUser({ id: `u-${Date.now()}`, username: `User_${users.length+1}`, role: UserRole.PROCUREMENT_MANAGER }, 'add')}
                  className="bg-slate-900 text-white px-4 py-2 rounded-lg text-sm font-bold hover:bg-slate-800 transition-colors"
                >
                  <i className="fa-solid fa-plus mr-2"></i> Create User
                </button>
             </div>
             <div className="divide-y">
               {users.map(u => (
                 <div key={u.id} className="py-4 flex justify-between items-center group">
                    <div className="flex items-center gap-4">
                      <div className="w-12 h-12 rounded-full bg-slate-100 flex items-center justify-center font-bold text-slate-400 group-hover:bg-emerald-100 group-hover:text-emerald-600 transition-colors">
                        {u.username.charAt(0).toUpperCase()}
                      </div>
                      <div>
                        <p className="font-bold text-slate-900">{u.username}</p>
                        <p className="text-xs text-slate-400 font-medium tracking-wide">{u.role}</p>
                      </div>
                    </div>
                    <div className="flex items-center gap-3">
                      <span className="px-3 py-1 bg-emerald-50 text-emerald-600 rounded-full text-[10px] font-bold">ACTIVE</span>
                      <button 
                        onClick={() => manageUser(u, 'delete')}
                        className="text-slate-300 hover:text-rose-500 p-2 transition-colors"
                      >
                        <i className="fa-solid fa-trash-can"></i>
                      </button>
                    </div>
                 </div>
               ))}
             </div>
          </div>
        )
      default:
        return <Dashboard suppliers={suppliers} materials={materials} procurement={procurement} energy={energy} />;
    }
  };

  return (
    <div className="min-h-screen bg-slate-50">
      <Sidebar 
        currentRole={currentUser.role} 
        activeTab={activeTab} 
        setActiveTab={setActiveTab} 
        onLogout={handleLogout} 
      />
      <main className="pl-64 min-h-screen transition-all">
        <div className="p-10 max-w-[1400px] mx-auto">
          {renderContent()}
        </div>
      </main>
    </div>
  );
};

export default App;

import React, { useState } from 'react';
import { Supplier, Material } from '../types';

interface MasterDataProps {
  suppliers: Supplier[];
  materials: Material[];
  onSupplierAction: (s: Supplier, mode: 'add' | 'edit' | 'delete') => void;
  onMaterialAction: (m: Material, mode: 'add' | 'edit' | 'delete') => void;
}

const MasterData: React.FC<MasterDataProps> = ({ suppliers, materials, onSupplierAction, onMaterialAction }) => {
  const [activeSubTab, setActiveSubTab] = useState<'suppliers' | 'materials'>('suppliers');
  const [isExporting, setIsExporting] = useState(false);
  const [showModal, setShowModal] = useState(false);
  const [editingItem, setEditingItem] = useState<any>(null);

  const handleExportData = () => {
    setIsExporting(true);
    setTimeout(() => {
      let csvContent = "";
      if (activeSubTab === 'suppliers') {
        const headers = ["ID", "Name", "Category", "Sustainability Score", "Certifications"];
        const rows = suppliers.map(s => [s.id, s.name, s.category, s.sustainabilityScore, s.certifications.join(" | ")]);
        csvContent = [headers, ...rows].map(e => e.join(",")).join("\n");
      } else {
        const headers = ["ID", "Name", "Category", "CO2 Factor", "Recyclability Rate", "Price/Unit"];
        const rows = materials.map(m => [m.id, m.name, m.category, m.carbonFactor, m.recyclabilityRate, m.averagePrice]);
        csvContent = [headers, ...rows].map(e => e.join(",")).join("\n");
      }
      const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' });
      const url = URL.createObjectURL(blob);
      const link = document.createElement("a");
      link.href = url;
      link.download = `master_data_${activeSubTab}.csv`;
      link.click();
      setIsExporting(false);
    }, 600);
  };

  const openModal = (item: any = null) => {
    setEditingItem(item);
    setShowModal(true);
  };

  const handleSave = (e: React.FormEvent) => {
    e.preventDefault();
    const formData = new FormData(e.currentTarget as HTMLFormElement);
    const mode = editingItem ? 'edit' : 'add';

    if (activeSubTab === 'suppliers') {
      const supplier: Supplier = {
        id: editingItem?.id || `s-${Date.now()}`,
        name: formData.get('name') as string,
        category: formData.get('category') as string,
        sustainabilityScore: Number(formData.get('score')),
        carbonEfficiency: 0,
        certifications: (formData.get('certs') as string).split(',').map(c => c.trim()).filter(c => c)
      };
      onSupplierAction(supplier, mode);
    } else {
      const material: Material = {
        id: editingItem?.id || `m-${Date.now()}`,
        name: formData.get('name') as string,
        category: formData.get('category') as string,
        unit: formData.get('unit') as string,
        carbonFactor: Number(formData.get('carbon')),
        recyclabilityRate: Number(formData.get('recyclability')),
        averagePrice: Number(formData.get('price'))
      };
      onMaterialAction(material, mode);
    }
    setShowModal(false);
  };

  return (
    <div className="space-y-6 animate-in fade-in duration-500">
      <header className="flex justify-between items-center">
        <div>
          <h2 className="text-3xl font-bold text-slate-900 tracking-tight">Master Data</h2>
          <p className="text-slate-500 mt-1">Configure foundational business entities.</p>
        </div>
        <div className="flex gap-3">
          <button onClick={handleExportData} disabled={isExporting} className="bg-white text-slate-700 px-5 py-2.5 rounded-xl font-bold border hover:bg-slate-50 transition-all flex items-center gap-2">
            <i className={`fa-solid ${isExporting ? 'fa-spinner animate-spin' : 'fa-file-export'}`}></i> Export
          </button>
          <button onClick={() => openModal()} className="bg-emerald-600 text-white px-5 py-2.5 rounded-xl font-bold hover:bg-emerald-700 transition-all shadow-lg">
            <i className="fa-solid fa-plus mr-2"></i> Create New
          </button>
        </div>
      </header>

      <div className="bg-white rounded-2xl border shadow-sm overflow-hidden">
        <div className="flex border-b">
          <button onClick={() => setActiveSubTab('suppliers')} className={`px-8 py-4 text-sm font-bold transition-all relative ${activeSubTab === 'suppliers' ? 'text-emerald-600' : 'text-slate-500'}`}>
            Suppliers List {activeSubTab === 'suppliers' && <div className="absolute bottom-0 left-0 w-full h-0.5 bg-emerald-600"></div>}
          </button>
          <button onClick={() => setActiveSubTab('materials')} className={`px-8 py-4 text-sm font-bold transition-all relative ${activeSubTab === 'materials' ? 'text-emerald-600' : 'text-slate-500'}`}>
            Materials Catalog {activeSubTab === 'materials' && <div className="absolute bottom-0 left-0 w-full h-0.5 bg-emerald-600"></div>}
          </button>
        </div>

        <div className="p-0">
          {activeSubTab === 'suppliers' ? (
            <table className="w-full text-left">
              <thead className="bg-slate-50 text-slate-500 text-xs uppercase font-bold tracking-wider">
                <tr><th className="px-6 py-4">Name</th><th className="px-6 py-4">Category</th><th className="px-6 py-4 text-center">Score</th><th className="px-6 py-4">Certs</th><th className="px-6 py-4 text-right">Actions</th></tr>
              </thead>
              <tbody className="divide-y text-sm">
                {suppliers.map(s => (
                  <tr key={s.id} className="hover:bg-slate-50 transition-colors">
                    <td className="px-6 py-4 font-bold text-slate-900">{s.name}</td>
                    <td className="px-6 py-4 text-slate-600">{s.category}</td>
                    <td className="px-6 py-4 text-center">
                      <span className={`inline-block px-3 py-1 rounded-full font-bold text-xs ${s.sustainabilityScore > 80 ? 'bg-emerald-100 text-emerald-700' : 'bg-amber-100 text-amber-700'}`}>
                        {s.sustainabilityScore}
                      </span>
                    </td>
                    <td className="px-6 py-4">
                      <div className="flex gap-1">
                        {s.certifications.slice(0, 2).map((c, i) => <span key={i} className="bg-slate-100 px-2 py-0.5 rounded text-[10px]">{c}</span>)}
                      </div>
                    </td>
                    <td className="px-6 py-4 text-right">
                      <button onClick={() => openModal(s)} className="text-slate-400 hover:text-blue-600 mr-3"><i className="fa-solid fa-pen"></i></button>
                      <button onClick={() => onSupplierAction(s, 'delete')} className="text-slate-400 hover:text-rose-600"><i className="fa-solid fa-trash"></i></button>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          ) : (
            <table className="w-full text-left">
              <thead className="bg-slate-50 text-slate-500 text-xs uppercase font-bold tracking-wider">
                <tr><th className="px-6 py-4">Name</th><th className="px-6 py-4">CO2 Factor</th><th className="px-6 py-4 text-center">Recyclable</th><th className="px-6 py-4">Price</th><th className="px-6 py-4 text-right">Actions</th></tr>
              </thead>
              <tbody className="divide-y text-sm">
                {materials.map(m => (
                  <tr key={m.id} className="hover:bg-slate-50 transition-colors">
                    <td className="px-6 py-4"><div className="font-bold text-slate-900">{m.name}</div><div className="text-xs text-slate-400">{m.category}</div></td>
                    <td className="px-6 py-4 font-mono text-slate-600">{m.carbonFactor}</td>
                    <td className="px-6 py-4 text-center font-bold text-slate-700">{m.recyclabilityRate}%</td>
                    <td className="px-6 py-4 font-medium">${m.averagePrice}</td>
                    <td className="px-6 py-4 text-right">
                      <button onClick={() => openModal(m)} className="text-slate-400 hover:text-blue-600 mr-3"><i className="fa-solid fa-pen"></i></button>
                      <button onClick={() => onMaterialAction(m, 'delete')} className="text-slate-400 hover:text-rose-600"><i className="fa-solid fa-trash"></i></button>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          )}
        </div>
      </div>

      {showModal && (
        <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-sm z-50 flex items-center justify-center p-4">
          <div className="bg-white w-full max-w-lg rounded-3xl p-8 shadow-2xl animate-in zoom-in duration-200">
            <h3 className="text-2xl font-bold mb-6">{editingItem ? 'Edit' : 'Create'} {activeSubTab === 'suppliers' ? 'Supplier' : 'Material'}</h3>
            <form onSubmit={handleSave} className="space-y-4">
              <div className="grid grid-cols-2 gap-4">
                <div className="col-span-2 space-y-1">
                  <label className="text-xs font-bold text-slate-500 uppercase">Name</label>
                  <input name="name" defaultValue={editingItem?.name} required className="w-full border p-3 rounded-xl focus:ring-2 focus:ring-emerald-500 outline-none" />
                </div>
                <div className="space-y-1">
                  <label className="text-xs font-bold text-slate-500 uppercase">Category</label>
                  <input name="category" defaultValue={editingItem?.category} required className="w-full border p-3 rounded-xl focus:ring-2 focus:ring-emerald-500 outline-none" />
                </div>
                {activeSubTab === 'suppliers' ? (
                  <>
                    <div className="space-y-1">
                      <label className="text-xs font-bold text-slate-500 uppercase">Score (0-100)</label>
                      <input name="score" type="number" defaultValue={editingItem?.sustainabilityScore} required className="w-full border p-3 rounded-xl focus:ring-2 focus:ring-emerald-500 outline-none" />
                    </div>
                    <div className="col-span-2 space-y-1">
                      <label className="text-xs font-bold text-slate-500 uppercase">Certifications (comma separated)</label>
                      <input name="certs" defaultValue={editingItem?.certifications?.join(', ')} className="w-full border p-3 rounded-xl focus:ring-2 focus:ring-emerald-500 outline-none" placeholder="ISO 14001, B-Corp" />
                    </div>
                  </>
                ) : (
                  <>
                    <div className="space-y-1">
                      <label className="text-xs font-bold text-slate-500 uppercase">Unit</label>
                      <input name="unit" defaultValue={editingItem?.unit || 'kg'} required className="w-full border p-3 rounded-xl focus:ring-2 focus:ring-emerald-500 outline-none" />
                    </div>
                    <div className="space-y-1">
                      <label className="text-xs font-bold text-slate-500 uppercase">Carbon Factor</label>
                      <input name="carbon" type="number" step="0.01" defaultValue={editingItem?.carbonFactor} required className="w-full border p-3 rounded-xl focus:ring-2 focus:ring-emerald-500 outline-none" />
                    </div>
                    <div className="space-y-1">
                      <label className="text-xs font-bold text-slate-500 uppercase">Recyclability %</label>
                      <input name="recyclability" type="number" defaultValue={editingItem?.recyclabilityRate} required className="w-full border p-3 rounded-xl focus:ring-2 focus:ring-emerald-500 outline-none" />
                    </div>
                    <div className="space-y-1">
                      <label className="text-xs font-bold text-slate-500 uppercase">Price / Unit</label>
                      <input name="price" type="number" step="0.01" defaultValue={editingItem?.averagePrice} required className="w-full border p-3 rounded-xl focus:ring-2 focus:ring-emerald-500 outline-none" />
                    </div>
                  </>
                )}
              </div>
              <div className="flex gap-3 mt-8">
                <button type="button" onClick={() => setShowModal(false)} className="flex-1 px-4 py-3 rounded-xl border font-bold text-slate-500 hover:bg-slate-50">Cancel</button>
                <button type="submit" className="flex-1 bg-emerald-600 text-white px-4 py-3 rounded-xl font-bold hover:bg-emerald-700 shadow-lg">Save Changes</button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

export default MasterData;

import React, { useState } from 'react';
import { Material, Supplier, ProcurementRecord, EnergyRecord } from '../types';

interface DataManagementProps {
  materials: Material[];
  suppliers: Supplier[];
  procurement: ProcurementRecord[];
  energy: EnergyRecord[];
  onAddProcurement: (p: Omit<ProcurementRecord, 'id'>) => void;
  onAddEnergy: (e: Omit<EnergyRecord, 'id'>) => void;
}

const DataManagement: React.FC<DataManagementProps> = ({ materials, suppliers, procurement, energy, onAddProcurement, onAddEnergy }) => {
  const [tab, setTab] = useState<'procurement' | 'energy'>('procurement');

  const [pFormData, setPFormData] = useState({
    date: new Date().toISOString().split('T')[0],
    materialId: '',
    supplierId: '',
    quantity: 0,
    totalCost: 0
  });

  const [eFormData, setEFormData] = useState({
    date: new Date().toISOString().split('T')[0],
    source: 'Electricity' as EnergyRecord['source'],
    amount: 0,
    unit: 'kWh',
    carbonEquivalent: 0
  });

  const handlePSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!pFormData.materialId || !pFormData.supplierId || pFormData.quantity <= 0) return;
    onAddProcurement(pFormData);
    setPFormData({ ...pFormData, quantity: 0, totalCost: 0 });
  };

  const handleESubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (eFormData.amount <= 0) return;
    const factors = { 'Electricity': 0.41, 'Natural Gas': 0.2, 'Solar': 0, 'Diesel': 2.68 };
    const carbon = eFormData.amount * (factors[eFormData.source] || 0);
    onAddEnergy({ ...eFormData, carbonEquivalent: carbon });
    setEFormData({ ...eFormData, amount: 0 });
  };

  return (
    <div className="space-y-10 animate-in fade-in duration-500">
      <header>
        <h2 className="text-3xl font-bold text-slate-900 tracking-tight">Data Entry & Management</h2>
        <p className="text-slate-500 mt-1">Record transactions and monitor historical data inputs.</p>
      </header>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-10">
        <div className="bg-white rounded-2xl border shadow-xl overflow-hidden self-start">
          <div className="flex bg-slate-50 border-b">
            <button onClick={() => setTab('procurement')} className={`flex-1 py-5 text-sm font-bold border-r ${tab === 'procurement' ? 'bg-white text-emerald-600 border-b-emerald-600' : 'text-slate-400'}`}>
              <i className="fa-solid fa-cart-shopping mr-2"></i> Procurement Log
            </button>
            <button onClick={() => setTab('energy')} className={`flex-1 py-5 text-sm font-bold ${tab === 'energy' ? 'bg-white text-amber-600 border-b-amber-600' : 'text-slate-400'}`}>
              <i className="fa-solid fa-bolt mr-2"></i> Energy Usage
            </button>
          </div>
          <div className="p-8">
