              <form onSubmit={handlePSubmit} className="space-y-4">
                <div className="grid grid-cols-2 gap-4">
                  <div className="space-y-1"><label className="text-xs font-bold text-slate-500">Date</label><input type="date" className="w-full border p-3 rounded-xl outline-none" value={pFormData.date} onChange={e => setPFormData({...pFormData, date: e.target.value})} /></div>
                  <div className="space-y-1"><label className="text-xs font-bold text-slate-500">Quantity</label><input type="number" className="w-full border p-3 rounded-xl outline-none" value={pFormData.quantity || ''} onChange={e => setPFormData({...pFormData, quantity: Number(e.target.value)})} /></div>
                </div>
                <div className="space-y-1"><label className="text-xs font-bold text-slate-500">Material</label>
                  <select className="w-full border p-3 rounded-xl outline-none" value={pFormData.materialId} onChange={e => setPFormData({...pFormData, materialId: e.target.value})}>
                    <option value="">Select Material...</option>
                    {materials.map(m => <option key={m.id} value={m.id}>{m.name}</option>)}
                  </select>
                </div>
                <div className="space-y-1"><label className="text-xs font-bold text-slate-500">Supplier</label>
                  <select className="w-full border p-3 rounded-xl outline-none" value={pFormData.supplierId} onChange={e => setPFormData({...pFormData, supplierId: e.target.value})}>
                    <option value="">Select Supplier...</option>
                    {suppliers.map(s => <option key={s.id} value={s.id}>{s.name}</option>)}
                  </select>
                </div>
                <div className="space-y-1"><label className="text-xs font-bold text-slate-500">Total Cost ($)</label><input type="number" className="w-full border p-3 rounded-xl outline-none" value={pFormData.totalCost || ''} onChange={e => setPFormData({...pFormData, totalCost: Number(e.target.value)})} /></div>
                <button type="submit" className="w-full bg-emerald-600 text-white py-4 rounded-xl font-bold shadow-lg mt-4">Record Transaction</button>
              </form>
            ) : (
              <form onSubmit={handleESubmit} className="space-y-4">
                <div className="grid grid-cols-2 gap-4">
                  <div className="space-y-1"><label className="text-xs font-bold text-slate-500">Date</label><input type="date" className="w-full border p-3 rounded-xl" value={eFormData.date} onChange={e => setEFormData({...eFormData, date: e.target.value})} /></div>
                  <div className="space-y-1"><label className="text-xs font-bold text-slate-500">Consumption</label><input type="number" className="w-full border p-3 rounded-xl" value={eFormData.amount || ''} onChange={e => setEFormData({...eFormData, amount: Number(e.target.value)})} /></div>
                </div>
                <div className="space-y-1"><label className="text-xs font-bold text-slate-500">Source</label>
                  <select className="w-full border p-3 rounded-xl" value={eFormData.source} onChange={e => setEFormData({...eFormData, source: e.target.value as any})}>
                    <option value="Electricity">Electricity</option><option value="Solar">Solar</option><option value="Natural Gas">Natural Gas</option><option value="Diesel">Diesel</option>
                  </select>
                </div>
                <button type="submit" className="w-full bg-amber-600 text-white py-4 rounded-xl font-bold shadow-lg mt-4">Record Usage</button>
              </form>
            )}
          </div>
        </div>

        <div className="space-y-6">
          <div className="bg-white rounded-2xl border p-6 shadow-sm">
            <h3 className="text-lg font-bold text-slate-900 mb-4">Recent Entries</h3>
            <div className="overflow-hidden">
              <table className="w-full text-left">
                <thead className="text-[10px] uppercase text-slate-400 font-bold border-b">
                  <tr><th className="py-2">Date</th><th className="py-2">Item/Source</th><th className="py-2 text-right">Value</th></tr>
                </thead>
                <tbody className="divide-y text-sm">
                  {tab === 'procurement' ? 
                    procurement.slice(0, 8).map(p => (
                      <tr key={p.id} className="hover:bg-slate-50">
                        <td className="py-3 text-slate-500">{p.date}</td>
                        <td className="py-3 font-bold text-slate-800">{materials.find(m => m.id === p.materialId)?.name}</td>
                        <td className="py-3 text-right text-emerald-600 font-bold">${p.totalCost}</td>
                      </tr>
                    )) : 
                    energy.slice(0, 8).map(e => (
                      <tr key={e.id} className="hover:bg-slate-50">
                        <td className="py-3 text-slate-500">{e.date}</td>
                        <td className="py-3 font-bold text-slate-800">{e.source}</td>
                        <td className="py-3 text-right text-amber-600 font-bold">{e.amount} {e.unit}</td>
                      </tr>
                    ))
                  }
                </tbody>
              </table>
            </div>
            {((tab === 'procurement' ? procurement : energy).length === 0) && (
              <p className="text-center text-slate-400 py-10">No data records found yet.</p>
            )}
          </div>
        </div>
      </div>
    </div>
  );
};

export default DataManagement;

import React, { useMemo, useState } from 'react';
import { Supplier, Material, ProcurementRecord, Recommendation } from '../types';

interface RecommendationEngineProps {
  suppliers: Supplier[];
  materials: Material[];
  procurement: ProcurementRecord[];
}

const RecommendationEngine: React.FC<RecommendationEngineProps> = ({ suppliers, materials, procurement }) => {
  const [applying, setApplying] = useState<string | null>(null);

  const recommendations = useMemo(() => {
    const recs: Recommendation[] = [];
    const highImpactMaterials = materials.filter(m => m.carbonFactor > 10);
    highImpactMaterials.forEach(m => {
      const alternative = materials.find(alt => alt.category === m.category && alt.carbonFactor < m.carbonFactor);
      if (alternative) {
        recs.push({
          id: `rec-m-${m.id}`,
          type: 'MATERIAL',
          title: `Switch Material: ${m.name}`,
          description: `Consider replacing '${m.name}' with '${alternative.name}' to reduce footprint by ${Math.round((1 - alternative.carbonFactor/m.carbonFactor) * 100)}%.`,
          impact: 'High'
        });
      }
    });

    const activeSupplierIds = new Set(procurement.map(p => p.supplierId));
    suppliers.filter(s => activeSupplierIds.has(s.id) && s.sustainabilityScore < 60).forEach(s => {
      const betterSupplier = suppliers.find(alt => alt.category === s.category && alt.sustainabilityScore > 80);
      if (betterSupplier) {
        recs.push({
          id: `rec-s-${s.id}`,
          type: 'SUPPLIER',
          title: `Supplier Shift: ${s.name}`,
          description: `Switching to '${betterSupplier.name}' (Score: ${betterSupplier.sustainabilityScore}) improves your rating.`,
          impact: 'Medium'
        });
      }
    });

    if (procurement.length > 5) {
      recs.push({
        id: 'rec-opt-1',
        type: 'OPTIMIZATION',
        title: 'Route Consolidation',
        description: 'Optimize shipment frequency to lower Scope 3 transportation emissions.',
        impact: 'Low'
      });
    }
    return recs;
  }, [suppliers, materials, procurement]);

  const handleApply = (id: string) => {
    setApplying(id);
    setTimeout(() => {
      setApplying(null);
      alert("Simulation: This strategy has been added to the procurement policy for future orders.");
    }, 1200);
  };

  return (
    <div className="space-y-6 animate-in slide-in-from-bottom duration-500">
      <header>
        <h2 className="text-3xl font-bold text-slate-900 tracking-tight">Smart Insights</h2>
        <p className="text-slate-500 mt-1">Automated decision support based on procurement logic.</p>
      </header>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
        {recommendations.map(rec => (
          <div key={rec.id} className="bg-white rounded-2xl border p-6 shadow-sm flex flex-col group relative">
            <div className={`absolute top-0 right-0 p-4 opacity-5 group-hover:opacity-20 transition-opacity`}>
              <i className={`fa-solid ${rec.type === 'MATERIAL' ? 'fa-box' : 'fa-truck'} text-6xl`}></i>
            </div>
            <div className="flex items-center justify-between mb-4">
              <span className={`px-2 py-0.5 rounded-full text-[10px] font-bold uppercase ${rec.impact === 'High' ? 'bg-rose-100 text-rose-600' : 'bg-blue-100 text-blue-600'}`}>
                {rec.impact} Impact
              </span>
            </div>
            <h3 className="text-lg font-bold text-slate-900 mb-2">{rec.title}</h3>
            <p className="text-slate-500 text-sm leading-relaxed mb-6">{rec.description}</p>
            <button 
              onClick={() => handleApply(rec.id)}
              disabled={!!applying}
              className="mt-auto w-full bg-slate-50 text-emerald-600 py-2.5 rounded-xl font-bold text-sm hover:bg-emerald-600 hover:text-white transition-all flex items-center justify-center gap-2"
            >
              {applying === rec.id ? <i className="fa-solid fa-spinner animate-spin"></i> : 'Apply Strategy'}
            </button>
          </div>
        ))}
      </div>

      <div className="bg-emerald-900 rounded-3xl p-8 text-white relative overflow-hidden mt-10">
        <div className="relative z-10 max-w-xl">
          <h3 className="text-2xl font-bold mb-3">Rule-Based Efficiency</h3>
          <p className="text-emerald-100 opacity-80">This engine maps materials and suppliers to environmental benchmarks. High-emission sources are flagged automatically to support your sustainability goals.</p>
        </div>
      </div>
    </div>
  );
};

export default RecommendationEngine;

import React, { useState, useEffect } from 'react';
import { Supplier, Material } from '../types';

interface MasterDataProps {
  suppliers: Supplier[];
  materials: Material[];
  onSupplierAction: (s: Supplier, mode: 'add' | 'edit' | 'delete') => void;
  onMaterialAction: (m: Material, mode: 'add' | 'edit' | 'delete') => void;
}

const MasterData: React.FC<MasterDataProps> = ({ suppliers, materials, onSupplierAction, onMaterialAction }) => {
  const [activeSubTab, setActiveSubTab] = useState<'suppliers' | 'materials'>('suppliers');
  const [isExporting, setIsExporting] = useState(false);
  const [showModal, setShowModal] = useState(false);
  const [editingItem, setEditingItem] = useState<any>(null);
  const [errors, setErrors] = useState<Record<string, string>>({});

  const handleExportData = () => {
    setIsExporting(true);
    setTimeout(() => {
      let csvContent = "";
      if (activeSubTab === 'suppliers') {
        const headers = ["ID", "Name", "Category", "Sustainability Score", "Certifications"];
        const rows = suppliers.map(s => [s.id, s.name, s.category, s.sustainabilityScore, s.certifications.join(" | ")]);
        csvContent = [headers, ...rows].map(e => e.join(",")).join("\n");
      } else {
        const headers = ["ID", "Name", "Category", "CO2 Factor", "Recyclability Rate", "Price/Unit"];
        const rows = materials.map(m => [m.id, m.name, m.category, m.carbonFactor, m.recyclabilityRate, m.averagePrice]);
        csvContent = [headers, ...rows].map(e => e.join(",")).join("\n");
      }
      const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' });
      const url = URL.createObjectURL(blob);
      const link = document.createElement("a");
      link.href = url;
      link.download = `master_data_${activeSubTab}.csv`;
      link.click();
      setIsExporting(false);
    }, 600);
  };

  const openModal = (item: any = null) => {
    setEditingItem(item);
    setErrors({});
    setShowModal(true);
  };

  const handleSave = (e: React.FormEvent) => {
    e.preventDefault();
    const formData = new FormData(e.currentTarget as HTMLFormElement);
    const newErrors: Record<string, string> = {};

    // Validation
    const name = formData.get('name') as string;
    const category = formData.get('category') as string;

    if (!name.trim()) newErrors.name = "Name is required";
    if (!category.trim()) newErrors.category = "Category is required";

    if (activeSubTab === 'suppliers') {
      const score = Number(formData.get('score'));
      if (isNaN(score) || score < 0 || score > 100) newErrors.score = "Score must be between 0 and 100";
    } else {
      const carbon = Number(formData.get('carbon'));
      const recyclability = Number(formData.get('recyclability'));
      const price = Number(formData.get('price'));
      if (isNaN(carbon) || carbon < 0) newErrors.carbon = "Valid carbon factor required";
      if (isNaN(recyclability) || recyclability < 0 || recyclability > 100) newErrors.recyclability = "Recyclability must be 0-100%";
      if (isNaN(price) || price < 0) newErrors.price = "Valid price required";
    }

    if (Object.keys(newErrors).length > 0) {
      setErrors(newErrors);
      return;
    }

    const mode = editingItem ? 'edit' : 'add';

    if (activeSubTab === 'suppliers') {
      const supplier: Supplier = {
        id: editingItem?.id || `s-${Date.now()}`,
        name: name,
        category: category,
        sustainabilityScore: Number(formData.get('score')),
        carbonEfficiency: 0,
        certifications: (formData.get('certs') as string).split(',').map(c => c.trim()).filter(c => c)
      };
      onSupplierAction(supplier, mode);
    } else {
      const material: Material = {
        id: editingItem?.id || `m-${Date.now()}`,
        name: name,
        category: category,
        unit: formData.get('unit') as string,
        carbonFactor: Number(formData.get('carbon')),
        recyclabilityRate: Number(formData.get('recyclability')),
        averagePrice: Number(formData.get('price'))
      };
      onMaterialAction(material, mode);
    }
    setShowModal(false);
  };

  return (
    <div className="space-y-6 animate-in fade-in duration-500">
      <header className="flex justify-between items-center">
        <div>
          <h2 className="text-3xl font-bold text-slate-900 tracking-tight">Master Data</h2>
          <p className="text-slate-500 mt-1">Configure foundational business entities.</p>
        </div>
        <div className="flex gap-3">
          <button onClick={handleExportData} disabled={isExporting} className="bg-white text-slate-700 px-5 py-2.5 rounded-xl font-bold border hover:bg-slate-50 transition-all flex items-center gap-2">
            <i className={`fa-solid ${isExporting ? 'fa-spinner animate-spin' : 'fa-file-export'}`}></i> Export
          </button>
          <button onClick={() => openModal()} className="bg-emerald-600 text-white px-5 py-2.5 rounded-xl font-bold hover:bg-emerald-700 transition-all shadow-lg">
            <i className="fa-solid fa-plus mr-2"></i> Create New
          </button>
        </div>
      </header>

      <div className="bg-white rounded-2xl border shadow-sm overflow-hidden">
        <div className="flex border-b">
          <button onClick={() => setActiveSubTab('suppliers')} className={`px-8 py-4 text-sm font-bold transition-all relative ${activeSubTab === 'suppliers' ? 'text-emerald-600' : 'text-slate-500'}`}>
            Suppliers List {activeSubTab === 'suppliers' && <div className="absolute bottom-0 left-0 w-full h-0.5 bg-emerald-600"></div>}
          </button>
          <button onClick={() => setActiveSubTab('materials')} className={`px-8 py-4 text-sm font-bold transition-all relative ${activeSubTab === 'materials' ? 'text-emerald-600' : 'text-slate-500'}`}>
            Materials Catalog {activeSubTab === 'materials' && <div className="absolute bottom-0 left-0 w-full h-0.5 bg-emerald-600"></div>}
          </button>
        </div>

        <div className="p-0">
          {activeSubTab === 'suppliers' ? (
            <table className="w-full text-left">
              <thead className="bg-slate-50 text-slate-500 text-xs uppercase font-bold tracking-wider">
                <tr><th className="px-6 py-4">Name</th><th className="px-6 py-4">Category</th><th className="px-6 py-4 text-center">Score</th><th className="px-6 py-4">Certs</th><th className="px-6 py-4 text-right">Actions</th></tr>
              </thead>
              <tbody className="divide-y text-sm">
                {suppliers.length > 0 ? suppliers.map(s => (
                  <tr key={s.id} className="hover:bg-slate-50 transition-colors">
                    <td className="px-6 py-4 font-bold text-slate-900">{s.name}</td>
                    <td className="px-6 py-4 text-slate-600">{s.category}</td>
                    <td className="px-6 py-4 text-center">
                      <span className={`inline-block px-3 py-1 rounded-full font-bold text-xs ${s.sustainabilityScore > 80 ? 'bg-emerald-100 text-emerald-700' : 'bg-amber-100 text-amber-700'}`}>
                        {s.sustainabilityScore}
                      </span>
                    </td>
                    <td className="px-6 py-4">
                      <div className="flex gap-1">
                        {s.certifications.slice(0, 2).map((c, i) => <span key={i} className="bg-slate-100 px-2 py-0.5 rounded text-[10px]">{c}</span>)}
                      </div>
                    </td>
                    <td className="px-6 py-4 text-right">
                      <button onClick={() => openModal(s)} className="text-slate-400 hover:text-blue-600 mr-3"><i className="fa-solid fa-pen"></i></button>
                      <button onClick={() => onSupplierAction(s, 'delete')} className="text-slate-400 hover:text-rose-600"><i className="fa-solid fa-trash"></i></button>
                    </td>
                  </tr>
                )) : <tr><td colSpan={5} className="p-10 text-center text-slate-400">No suppliers found.</td></tr>}
              </tbody>
            </table>
          ) : (
            <table className="w-full text-left">
              <thead className="bg-slate-50 text-slate-500 text-xs uppercase font-bold tracking-wider">
                <tr><th className="px-6 py-4">Name</th><th className="px-6 py-4">CO2 Factor</th><th className="px-6 py-4 text-center">Recyclable</th><th className="px-6 py-4">Price</th><th className="px-6 py-4 text-right">Actions</th></tr>
              </thead>
              <tbody className="divide-y text-sm">
                {materials.length > 0 ? materials.map(m => (
                  <tr key={m.id} className="hover:bg-slate-50 transition-colors">
                    <td className="px-6 py-4"><div className="font-bold text-slate-900">{m.name}</div><div className="text-xs text-slate-400">{m.category}</div></td>
                    <td className="px-6 py-4 font-mono text-slate-600">{m.carbonFactor}</td>
                    <td className="px-6 py-4 text-center font-bold text-slate-700">{m.recyclabilityRate}%</td>
                    <td className="px-6 py-4 font-medium">${m.averagePrice}</td>
                    <td className="px-6 py-4 text-right">
                      <button onClick={() => openModal(m)} className="text-slate-400 hover:text-blue-600 mr-3"><i className="fa-solid fa-pen"></i></button>
                      <button onClick={() => onMaterialAction(m, 'delete')} className="text-slate-400 hover:text-rose-600"><i className="fa-solid fa-trash"></i></button>
                    </td>
                  </tr>
                )) : <tr><td colSpan={5} className="p-10 text-center text-slate-400">No materials found.</td></tr>}
              </tbody>
            </table>
          )}
        </div>
      </div>

      {showModal && (
        <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-sm z-50 flex items-center justify-center p-4">
          <div className="bg-white w-full max-w-lg rounded-3xl p-8 shadow-2xl animate-in zoom-in duration-200">
            <h3 className="text-2xl font-bold mb-6">{editingItem ? 'Edit' : 'Create'} {activeSubTab === 'suppliers' ? 'Supplier' : 'Material'}</h3>
            <form onSubmit={handleSave} className="space-y-4">
              <div className="grid grid-cols-2 gap-4">
                <div className="col-span-2 space-y-1">
                  <label className="text-xs font-bold text-slate-500 uppercase">Name</label>
                  <input name="name" defaultValue={editingItem?.name} className={`w-full border p-3 rounded-xl focus:ring-2 focus:ring-emerald-500 outline-none ${errors.name ? 'border-rose-500' : 'border-slate-200'}`} />
                  {errors.name && <p className="text-rose-500 text-[10px] font-bold mt-1">{errors.name}</p>}
                </div>
                <div className="space-y-1">
                  <label className="text-xs font-bold text-slate-500 uppercase">Category</label>
                  <input name="category" defaultValue={editingItem?.category} className={`w-full border p-3 rounded-xl focus:ring-2 focus:ring-emerald-500 outline-none ${errors.category ? 'border-rose-500' : 'border-slate-200'}`} />
                  {errors.category && <p className="text-rose-500 text-[10px] font-bold mt-1">{errors.category}</p>}
                </div>
                {activeSubTab === 'suppliers' ? (
                  <>
                    <div className="space-y-1">
                      <label className="text-xs font-bold text-slate-500 uppercase">Score (0-100)</label>
                      <input name="score" type="number" defaultValue={editingItem?.sustainabilityScore} className={`w-full border p-3 rounded-xl focus:ring-2 focus:ring-emerald-500 outline-none ${errors.score ? 'border-rose-500' : 'border-slate-200'}`} />
                      {errors.score && <p className="text-rose-500 text-[10px] font-bold mt-1">{errors.score}</p>}
                    </div>
                    <div className="col-span-2 space-y-1">
                      <label className="text-xs font-bold text-slate-500 uppercase">Certifications (comma separated)</label>
                      <input name="certs" defaultValue={editingItem?.certifications?.join(', ')} className="w-full border p-3 border-slate-200 rounded-xl focus:ring-2 focus:ring-emerald-500 outline-none" placeholder="ISO 14001, B-Corp" />
                    </div>
                  </>
                ) : (
                  <>
                    <div className="space-y-1">
                      <label className="text-xs font-bold text-slate-500 uppercase">Unit</label>
                      <input name="unit" defaultValue={editingItem?.unit || 'kg'} className="w-full border border-slate-200 p-3 rounded-xl focus:ring-2 focus:ring-emerald-500 outline-none" />
                    </div>
                    <div className="space-y-1">
                      <label className="text-xs font-bold text-slate-500 uppercase">Carbon Factor</label>
                      <input name="carbon" type="number" step="0.01" defaultValue={editingItem?.carbonFactor} className={`w-full border p-3 rounded-xl focus:ring-2 focus:ring-emerald-500 outline-none ${errors.carbon ? 'border-rose-500' : 'border-slate-200'}`} />
                      {errors.carbon && <p className="text-rose-500 text-[10px] font-bold mt-1">{errors.carbon}</p>}
                    </div>
                    <div className="space-y-1">
                      <label className="text-xs font-bold text-slate-500 uppercase">Recyclability %</label>
                      <input name="recyclability" type="number" defaultValue={editingItem?.recyclabilityRate} className={`w-full border p-3 rounded-xl focus:ring-2 focus:ring-emerald-500 outline-none ${errors.recyclability ? 'border-rose-500' : 'border-slate-200'}`} />
                      {errors.recyclability && <p className="text-rose-500 text-[10px] font-bold mt-1">{errors.recyclability}</p>}
                    </div>
                    <div className="space-y-1">
                      <label className="text-xs font-bold text-slate-500 uppercase">Price / Unit</label>
                      <input name="price" type="number" step="0.01" defaultValue={editingItem?.averagePrice} className={`w-full border p-3 rounded-xl focus:ring-2 focus:ring-emerald-500 outline-none ${errors.price ? 'border-rose-500' : 'border-slate-200'}`} />
                      {errors.price && <p className="text-rose-500 text-[10px] font-bold mt-1">{errors.price}</p>}
                    </div>
                  </>
                )}
              </div>
              <div className="flex gap-3 mt-8">
                <button type="button" onClick={() => setShowModal(false)} className="flex-1 px-4 py-3 rounded-xl border font-bold text-slate-500 hover:bg-slate-50">Cancel</button>
                <button type="submit" className="flex-1 bg-emerald-600 text-white px-4 py-3 rounded-xl font-bold hover:bg-emerald-700 shadow-lg">Save Changes</button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

