import React, { useState } from 'react';
import { Material, Supplier, ProcurementRecord, EnergyRecord } from '../types';

interface DataManagementProps {
  materials: Material[];
  suppliers: Supplier[];
  procurement: ProcurementRecord[];
  energy: EnergyRecord[];
  onAddProcurement: (p: Omit<ProcurementRecord, 'id'>) => void;
  onAddEnergy: (e: Omit<EnergyRecord, 'id'>) => void;
}

const DataManagement: React.FC<DataManagementProps> = ({ materials, suppliers, procurement, energy, onAddProcurement, onAddEnergy }) => {
  const [tab, setTab] = useState<'procurement' | 'energy'>('procurement');
  const [successMsg, setSuccessMsg] = useState<string | null>(null);
  const [errors, setErrors] = useState<Record<string, string>>({});

  const [pFormData, setPFormData] = useState({
    date: new Date().toISOString().split('T')[0],
    materialId: '',
    supplierId: '',
    quantity: 0,
    totalCost: 0
  });

  const [eFormData, setEFormData] = useState({
    date: new Date().toISOString().split('T')[0],
    source: 'Electricity' as EnergyRecord['source'],
    amount: 0,
    unit: 'kWh',
    carbonEquivalent: 0
  });

  const showSuccess = (msg: string) => {
    setSuccessMsg(msg);
    setTimeout(() => setSuccessMsg(null), 3000);
  };

  const handlePSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    const newErrors: Record<string, string> = {};
    if (!pFormData.materialId) newErrors.materialId = "Material is required";
    if (!pFormData.supplierId) newErrors.supplierId = "Supplier is required";
    if (pFormData.quantity <= 0) newErrors.quantity = "Quantity must be > 0";
    if (pFormData.totalCost <= 0) newErrors.totalCost = "Cost must be > 0";

    if (Object.keys(newErrors).length > 0) {
      setErrors(newErrors);
      return;
    }

    onAddProcurement(pFormData);
    setPFormData({ ...pFormData, quantity: 0, totalCost: 0 });
    setErrors({});
    showSuccess("Procurement transaction logged!");
  };

  const handleESubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (eFormData.amount <= 0) {
      setErrors({ amount: "Amount must be greater than 0" });
      return;
    }
    const factors = { 'Electricity': 0.41, 'Natural Gas': 0.2, 'Solar': 0, 'Diesel': 2.68 };
    const carbon = eFormData.amount * (factors[eFormData.source] || 0);
    onAddEnergy({ ...eFormData, carbonEquivalent: carbon });
    setEFormData({ ...eFormData, amount: 0 });
    setErrors({});
    showSuccess("Energy consumption recorded!");
  };

  return (
    <div className="space-y-10 animate-in fade-in duration-500">
      <header className="flex justify-between items-start">
        <div>
          <h2 className="text-3xl font-bold text-slate-900 tracking-tight">Data Entry & Management</h2>
          <p className="text-slate-500 mt-1">Record transactions and monitor historical data inputs.</p>
        </div>
        {successMsg && (
          <div className="bg-emerald-50 text-emerald-600 px-4 py-2 rounded-lg border border-emerald-100 flex items-center gap-2 animate-bounce">
            <i className="fa-solid fa-check-circle"></i>
            <span className="text-sm font-bold">{successMsg}</span>
          </div>
        )}
      </header>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-10">
        <div className="bg-white rounded-2xl border shadow-xl overflow-hidden self-start">
          <div className="flex bg-slate-50 border-b">
            <button onClick={() => { setTab('procurement'); setErrors({}); }} className={`flex-1 py-5 text-sm font-bold border-r transition-all ${tab === 'procurement' ? 'bg-white text-emerald-600 border-b-2 border-b-emerald-600' : 'text-slate-400'}`}>
              <i className="fa-solid fa-cart-shopping mr-2"></i> Procurement Log
            </button>
            <button onClick={() => { setTab('energy'); setErrors({}); }} className={`flex-1 py-5 text-sm font-bold transition-all ${tab === 'energy' ? 'bg-white text-amber-600 border-b-2 border-b-amber-600' : 'text-slate-400'}`}>
              <i className="fa-solid fa-bolt mr-2"></i> Energy Usage
            </button>
          </div>
          <div className="p-8">
            {tab === 'procurement' ? (
              <form onSubmit={handlePSubmit} className="space-y-4">
                <div className="grid grid-cols-2 gap-4">
                  <div className="space-y-1">
                    <label className="text-xs font-bold text-slate-500 uppercase tracking-wide">Date</label>
                    <input type="date" className="w-full border border-slate-200 p-3 rounded-xl outline-none" value={pFormData.date} onChange={e => setPFormData({...pFormData, date: e.target.value})} />
                  </div>
                  <div className="space-y-1">
                    <label className="text-xs font-bold text-slate-500 uppercase tracking-wide">Quantity</label>
                    <input type="number" className={`w-full border p-3 rounded-xl outline-none ${errors.quantity ? 'border-rose-500' : 'border-slate-200'}`} value={pFormData.quantity || ''} onChange={e => setPFormData({...pFormData, quantity: Number(e.target.value)})} />
                    {errors.quantity && <p className="text-rose-500 text-[10px] font-bold">{errors.quantity}</p>}
                  </div>
                </div>
                <div className="space-y-1">
                  <label className="text-xs font-bold text-slate-500 uppercase tracking-wide">Material</label>
                  <select className={`w-full border p-3 rounded-xl outline-none ${errors.materialId ? 'border-rose-500' : 'border-slate-200'}`} value={pFormData.materialId} onChange={e => setPFormData({...pFormData, materialId: e.target.value})}>
                    <option value="">Select Material...</option>
                    {materials.map(m => <option key={m.id} value={m.id}>{m.name}</option>)}
                  </select>
                  {errors.materialId && <p className="text-rose-500 text-[10px] font-bold">{errors.materialId}</p>}
                </div>
                <div className="space-y-1">
                  <label className="text-xs font-bold text-slate-500 uppercase tracking-wide">Supplier</label>
                  <select className={`w-full border p-3 rounded-xl outline-none ${errors.supplierId ? 'border-rose-500' : 'border-slate-200'}`} value={pFormData.supplierId} onChange={e => setPFormData({...pFormData, supplierId: e.target.value})}>
                    <option value="">Select Supplier...</option>
                    {suppliers.map(s => <option key={s.id} value={s.id}>{s.name}</option>)}
                  </select>
                  {errors.supplierId && <p className="text-rose-500 text-[10px] font-bold">{errors.supplierId}</p>}
                </div>
                <div className="space-y-1">
                  <label className="text-xs font-bold text-slate-500 uppercase tracking-wide">Total Cost ($)</label>
                  <input type="number" className={`w-full border p-3 rounded-xl outline-none ${errors.totalCost ? 'border-rose-500' : 'border-slate-200'}`} value={pFormData.totalCost || ''} onChange={e => setPFormData({...pFormData, totalCost: Number(e.target.value)})} />
                  {errors.totalCost && <p className="text-rose-500 text-[10px] font-bold">{errors.totalCost}</p>}
                </div>
                <button type="submit" className="w-full bg-emerald-600 text-white py-4 rounded-xl font-bold shadow-lg mt-4 hover:bg-emerald-700 transition-colors">Record Transaction</button>
              </form>
            ) : (
              <form onSubmit={handleESubmit} className="space-y-4">
                <div className="grid grid-cols-2 gap-4">
                  <div className="space-y-1">
                    <label className="text-xs font-bold text-slate-500 uppercase tracking-wide">Date</label>
                    <input type="date" className="w-full border border-slate-200 p-3 rounded-xl" value={eFormData.date} onChange={e => setEFormData({...eFormData, date: e.target.value})} />
                  </div>
                  <div className="space-y-1">
                    <label className="text-xs font-bold text-slate-500 uppercase tracking-wide">Consumption</label>
                    <input type="number" className={`w-full border p-3 rounded-xl ${errors.amount ? 'border-rose-500' : 'border-slate-200'}`} value={eFormData.amount || ''} onChange={e => setEFormData({...eFormData, amount: Number(e.target.value)})} />
                    {errors.amount && <p className="text-rose-500 text-[10px] font-bold">{errors.amount}</p>}
                  </div>
                </div>
                <div className="space-y-1">
                  <label className="text-xs font-bold text-slate-500 uppercase tracking-wide">Source</label>
                  <select className="w-full border border-slate-200 p-3 rounded-xl" value={eFormData.source} onChange={e => setEFormData({...eFormData, source: e.target.value as any})}>
                    <option value="Electricity">Electricity</option><option value="Solar">Solar</option><option value="Natural Gas">Natural Gas</option><option value="Diesel">Diesel</option>
                  </select>
                </div>
                <button type="submit" className="w-full bg-amber-600 text-white py-4 rounded-xl font-bold shadow-lg mt-4 hover:bg-amber-700 transition-colors">Record Usage</button>
              </form>
            )}
          </div>
        </div>

        <div className="space-y-6">
          <div className="bg-white rounded-2xl border p-6 shadow-sm">
            <div className="flex items-center justify-between mb-4">
              <h3 className="text-lg font-bold text-slate-900">Recent Logs</h3>
              <span className="text-[10px] font-bold text-slate-400 bg-slate-50 px-2 py-1 rounded">Last 8 Entries</span>
            </div>
            <div className="overflow-hidden">
              <table className="w-full text-left">
                <thead className="text-[10px] uppercase text-slate-400 font-bold border-b">
                  <tr><th className="py-2">Date</th><th className="py-2">Item/Source</th><th className="py-2 text-right">Value</th></tr>
                </thead>
                <tbody className="divide-y text-sm">
                  {tab === 'procurement' ? 
                    procurement.slice(0, 8).map(p => (
                      <tr key={p.id} className="hover:bg-slate-50">
                        <td className="py-3 text-slate-500">{p.date}</td>
                        <td className="py-3 font-bold text-slate-800">{materials.find(m => m.id === p.materialId)?.name}</td>
                        <td className="py-3 text-right text-emerald-600 font-bold">${p.totalCost}</td>
                      </tr>
                    )) : 
                    energy.slice(0, 8).map(e => (
                      <tr key={e.id} className="hover:bg-slate-50">
                        <td className="py-3 text-slate-500">{e.date}</td>
                        <td className="py-3 font-bold text-slate-800">{e.source}</td>
                        <td className="py-3 text-right text-amber-600 font-bold">{e.amount} {e.unit}</td>
                      </tr>
                    ))
                  }
                </tbody>
              </table>
            </div>
            {((tab === 'procurement' ? procurement : energy).length === 0) && (
              <div className="text-center py-20 flex flex-col items-center">
                <i className="fa-solid fa-folder-open text-slate-200 text-4xl mb-2"></i>
                <p className="text-slate-400 font-medium">No records found yet.</p>
              </div>
            )}
          </div>
        </div>
      </div>
    </div>
  );
};

export default DataManagement;

import React, { useState, useMemo } from 'react';
import { UserRole, User, Supplier, Material, ProcurementRecord, EnergyRecord } from './types';
import { INITIAL_USERS, INITIAL_SUPPLIERS, INITIAL_MATERIALS, INITIAL_PROCUREMENT, INITIAL_ENERGY } from './constants';
import Sidebar from './components/Sidebar';
import Dashboard from './views/Dashboard';
import MasterData from './views/MasterData';
import DataManagement from './views/DataManagement';
import RecommendationEngine from './views/RecommendationEngine';

const App: React.FC = () => {
  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [activeTab, setActiveTab] = useState('dashboard');
  const [isGeneratingReport, setIsGeneratingReport] = useState(false);
  const [showUserModal, setShowUserModal] = useState(false);

  // App State
  const [suppliers, setSuppliers] = useState<Supplier[]>(INITIAL_SUPPLIERS);
  const [materials, setMaterials] = useState<Material[]>(INITIAL_MATERIALS);
  const [procurement, setProcurement] = useState<ProcurementRecord[]>(INITIAL_PROCUREMENT);
  const [energy, setEnergy] = useState<EnergyRecord[]>(INITIAL_ENERGY);
  const [users, setUsers] = useState<User[]>(INITIAL_USERS);

  // Auth logic
  const [loginInput, setLoginInput] = useState({ username: '', role: UserRole.ADMIN });

  const handleLogin = (e: React.FormEvent) => {
    e.preventDefault();
    const user = users.find(u => u.username.toLowerCase() === loginInput.username.toLowerCase() && u.role === loginInput.role);
    if (user) {
      setCurrentUser(user);
    } else {
      alert('Invalid user credentials. For this prototype, try username "admin" with ADMIN role.');
    }
  };

  const handleLogout = () => {
    setCurrentUser(null);
    setActiveTab('dashboard');
  };

  // Data Handlers
  const addProcurement = (p: Omit<ProcurementRecord, 'id'>) => {
    setProcurement(prev => [{ ...p, id: `p-${Date.now()}` }, ...prev]);
  };

  const addEnergy = (e: Omit<EnergyRecord, 'id'>) => {
    setEnergy(prev => [{ ...e, id: `e-${Date.now()}` }, ...prev]);
  };

  const manageSupplier = (supplier: Supplier, mode: 'add' | 'edit' | 'delete') => {
    if (mode === 'add') setSuppliers(prev => [...prev, supplier]);
    if (mode === 'edit') setSuppliers(prev => prev.map(s => s.id === supplier.id ? supplier : s));
    if (mode === 'delete') setSuppliers(prev => prev.filter(s => s.id !== supplier.id));
  };

  const manageMaterial = (material: Material, mode: 'add' | 'edit' | 'delete') => {
    if (mode === 'add') setMaterials(prev => [...prev, material]);
    if (mode === 'edit') setMaterials(prev => prev.map(m => m.id === material.id ? material : m));
    if (mode === 'delete') setMaterials(prev => prev.filter(m => m.id !== material.id));
  };

  const handleCreateUser = (e: React.FormEvent) => {
    e.preventDefault();
    const formData = new FormData(e.currentTarget as HTMLFormElement);
    const username = formData.get('username') as string;
    const role = formData.get('role') as UserRole;

    if (!username.trim()) return alert("Username is required");

    const newUser: User = {
      id: `u-${Date.now()}`,
      username: username,
      role: role
    };

    setUsers(prev => [...prev, newUser]);
    setShowUserModal(false);
  };

  const deleteUser = (user: User) => {
    if (user.id === currentUser?.id) return alert("Cannot delete currently logged-in user.");
    if (confirm(`Are you sure you want to delete user "${user.username}"?`)) {
      setUsers(prev => prev.filter(u => u.id !== user.id));
    }
  };

  const handleGenerateReport = () => {
    setIsGeneratingReport(true);
    setTimeout(() => {
      const energyCarbon = energy.reduce((sum, e) => sum + e.carbonEquivalent, 0);
      const materialCarbon = procurement.reduce((sum, p) => {
        const mat = materials.find(m => m.id === p.materialId);
        return sum + (p.quantity * (mat?.carbonFactor || 0));
      }, 0);

      const reportData = [
        ["Annual Sustainability Report", "2023"],
        ["Generated By", currentUser?.username || "System"],
        [""],
        ["KPI SUMMARY"],
        ["Total Energy Carbon Footprint", energyCarbon + " kg CO2e"],
        ["Total Procurement Carbon Footprint", materialCarbon + " kg CO2e"],
        ["Total Cumulative Footprint", (energyCarbon + materialCarbon) + " kg CO2e"],
        [""],
        ["ENERGY CONSUMPTION DETAILS"],
        ["Source", "Date", "Amount", "CO2 Equivalent"],
        ...energy.map(e => [e.source, e.date, e.amount + " " + e.unit, e.carbonEquivalent + " kg"]),
        [""],
        ["PROCUREMENT LOGS"],
        ["Date", "Material", "Quantity", "Total Cost"],
        ...procurement.map(p => {
          const m = materials.find(mat => mat.id === p.materialId);
          return [p.date, m?.name || "Unknown", p.quantity, "$" + p.totalCost];
        })
      ];

      const csvContent = reportData.map(e => e.join(",")).join("\n");
      const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' });
      const link = document.createElement("a");
      const url = URL.createObjectURL(blob);
      link.setAttribute("href", url);
      link.setAttribute("download", `annual_sustainability_report_${new Date().getFullYear()}.csv`);
      link.style.visibility = 'hidden';
      document.body.appendChild(link);
      link.click();
      document.body.removeChild(link);

      setIsGeneratingReport(false);
      alert('Sustainability Report generated and downloaded successfully!');
    }, 1500);
  };

  if (!currentUser) {
    return (
      <div className="min-h-screen bg-slate-900 flex items-center justify-center p-4">
        <div className="bg-white w-full max-w-md rounded-3xl p-8 shadow-2xl animate-in zoom-in duration-300">
          <div className="text-center mb-8">
            <div className="w-16 h-16 bg-emerald-100 text-emerald-600 rounded-2xl flex items-center justify-center text-3xl mx-auto mb-4">
              <i className="fa-solid fa-leaf"></i>
            </div>
            <h1 className="text-3xl font-extrabold text-slate-900">Green ERP</h1>
            <p className="text-slate-500 mt-2 font-medium">Sustainability Decision Support</p>
          </div>

          <form onSubmit={handleLogin} className="space-y-6">
            <div className="space-y-2">
              <label className="text-xs font-bold text-slate-500 uppercase tracking-widest ml-1">Username</label>
              <input 
                type="text" 
                className="w-full bg-slate-50 border border-slate-100 p-4 rounded-xl focus:ring-2 focus:ring-emerald-500 outline-none transition-all font-medium" 
                placeholder="e.g. admin"
                value={loginInput.username}
                onChange={e => setLoginInput({...loginInput, username: e.target.value})}
                required
              />
            </div>

            <div className="space-y-2">
              <label className="text-xs font-bold text-slate-500 uppercase tracking-widest ml-1">Select Role</label>
              <div className="grid grid-cols-1 gap-2">
                {[UserRole.ADMIN, UserRole.PROCUREMENT_MANAGER, UserRole.SUSTAINABILITY_MANAGER].map(role => (
                  <button
                    key={role}
                    type="button"
                    onClick={() => setLoginInput({...loginInput, role})}
                    className={`text-left px-4 py-3 rounded-xl border text-sm font-semibold transition-all ${
                      loginInput.role === role 
                        ? 'border-emerald-500 bg-emerald-50 text-emerald-700' 
                        : 'border-slate-100 bg-slate-50 text-slate-400 hover:border-emerald-200'
                    }`}
                  >
                    <i className={`fa-solid ${role === UserRole.ADMIN ? 'fa-user-shield' : role === UserRole.PROCUREMENT_MANAGER ? 'fa-truck-ramp-box' : 'fa-seedling'} mr-2`}></i>
                    {role.replace('_', ' ')}
                  </button>
                ))}
              </div>
            </div>

            <button type="submit" className="w-full bg-slate-900 text-white py-4 rounded-xl font-bold text-lg hover:bg-emerald-600 transition-all shadow-xl hover:shadow-emerald-200/50 flex items-center justify-center gap-2">
              Launch Portal
              <i className="fa-solid fa-arrow-right"></i>
            </button>
          </form>

          <div className="mt-8 pt-6 border-t border-slate-100 text-center">
             <p className="text-xs text-slate-400">© 2024 Green ERP System - MCA Final Year Project</p>
          </div>
        </div>
      </div>
    );
  }

  const renderContent = () => {
    switch(activeTab) {
      case 'dashboard':
        return <Dashboard suppliers={suppliers} materials={materials} procurement={procurement} energy={energy} />;
      case 'master-data':
        return <MasterData suppliers={suppliers} materials={materials} onSupplierAction={manageSupplier} onMaterialAction={manageMaterial} />;
      case 'data-management':
        return (
          <DataManagement 
            materials={materials} 
            suppliers={suppliers} 
            procurement={procurement}
            energy={energy}
            onAddProcurement={addProcurement} 
            onAddEnergy={addEnergy} 
          />
        );
      case 'recommendations':
        return <RecommendationEngine suppliers={suppliers} materials={materials} procurement={procurement} />;
      case 'reports':
        return (
          <div className="flex flex-col items-center justify-center py-24 space-y-6">
             <div className="w-24 h-24 bg-white rounded-full flex items-center justify-center shadow-xl border border-slate-100 mb-2">
                <i className={`fa-solid ${isGeneratingReport ? 'fa-spinner animate-spin text-emerald-500' : 'fa-file-pdf text-slate-300'} text-5xl`}></i>
             </div>
             <div className="text-center">
                <h3 className="text-2xl font-bold text-slate-900">Sustainability Reporting</h3>
                <p className="text-slate-500 text-center max-w-md mt-2">Generate comprehensive GHG Protocol-aligned carbon reports and supplier performance summaries in one click.</p>
             </div>
             <button 
                onClick={handleGenerateReport}
                disabled={isGeneratingReport}
                className={`bg-emerald-600 text-white px-8 py-3 rounded-xl font-bold hover:bg-emerald-700 transition-all shadow-lg flex items-center gap-2 ${isGeneratingReport ? 'opacity-70 cursor-wait' : ''}`}
             >
               {isGeneratingReport ? 'Compiling Dataset...' : 'Generate Annual Report'}
               {!isGeneratingReport && <i className="fa-solid fa-bolt"></i>}
             </button>
          </div>
        );
      case 'users':
        return (
          <div className="bg-white p-8 rounded-2xl border shadow-sm max-w-4xl mx-auto">
             <div className="flex justify-between items-center mb-8">
                <div>
                  <h3 className="text-2xl font-bold text-slate-900 tracking-tight">System Users</h3>
                  <p className="text-slate-500 text-sm mt-1">Manage platform access and assign roles.</p>
                </div>
                <button 
                  onClick={() => setShowUserModal(true)}
                  className="bg-slate-900 text-white px-5 py-2.5 rounded-xl text-sm font-bold hover:bg-slate-800 transition-all shadow-lg"
                >
                  <i className="fa-solid fa-plus mr-2"></i> Add New User
                </button>
             </div>
             <div className="divide-y border-t">
               {users.map(u => (
                 <div key={u.id} className="py-5 flex justify-between items-center group transition-colors hover:bg-slate-50 px-2 rounded-lg">
                    <div className="flex items-center gap-4">
                      <div className="w-12 h-12 rounded-full bg-slate-100 flex items-center justify-center font-bold text-slate-400 group-hover:bg-emerald-100 group-hover:text-emerald-600 transition-colors">
                        {u.username.charAt(0).toUpperCase()}
                      </div>
                      <div>
                        <p className="font-bold text-slate-900">{u.username}</p>
                        <p className="text-xs text-slate-400 font-bold tracking-wide uppercase">{u.role.replace('_', ' ')}</p>
                      </div>
                    </div>
                    <div className="flex items-center gap-3">
                      <span className="px-3 py-1 bg-emerald-50 text-emerald-600 rounded-full text-[10px] font-bold">ACTIVE</span>
                      <button 
                        onClick={() => deleteUser(u)}
                        className="text-slate-300 hover:text-rose-500 p-2 transition-colors"
                        title="Remove User"
                      >
                        <i className="fa-solid fa-trash-can"></i>
                      </button>
                    </div>
                 </div>
               ))}
             </div>

             {showUserModal && (
               <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-sm z-[100] flex items-center justify-center p-4">
                 <div className="bg-white w-full max-w-md rounded-3xl p-8 shadow-2xl animate-in zoom-in duration-200">
                    <div className="flex justify-between items-center mb-6">
                      <h3 className="text-2xl font-bold text-slate-900">Add New User</h3>
                      <button onClick={() => setShowUserModal(false)} className="text-slate-400 hover:text-slate-600"><i className="fa-solid fa-xmark text-xl"></i></button>
                    </div>
                    <form onSubmit={handleCreateUser} className="space-y-4">
                      <div className="space-y-1">
                        <label className="text-xs font-bold text-slate-500 uppercase">Username</label>
                        <input name="username" required className="w-full border border-slate-200 p-3 rounded-xl focus:ring-2 focus:ring-emerald-500 outline-none" placeholder="Enter name..." />
                      </div>
                      <div className="space-y-1">
                        <label className="text-xs font-bold text-slate-500 uppercase">Assign Role</label>
                        <select name="role" required className="w-full border border-slate-200 p-3 rounded-xl focus:ring-2 focus:ring-emerald-500 outline-none">
                          <option value={UserRole.PROCUREMENT_MANAGER}>Procurement Manager</option>
                          <option value={UserRole.SUSTAINABILITY_MANAGER}>Sustainability Manager</option>
                          <option value={UserRole.ADMIN}>Administrator</option>
                        </select>
                      </div>
                      <div className="flex gap-3 mt-8">
                        <button type="button" onClick={() => setShowUserModal(false)} className="flex-1 px-4 py-3 rounded-xl border font-bold text-slate-500 hover:bg-slate-50">Cancel</button>
                        <button type="submit" className="flex-1 bg-emerald-600 text-white px-4 py-3 rounded-xl font-bold hover:bg-emerald-700 shadow-lg">Save User</button>
                      </div>
                    </form>
                 </div>
               </div>
             )}
          </div>
        )
      default:
        return <Dashboard suppliers={suppliers} materials={materials} procurement={procurement} energy={energy} />;
    }
  };

  return (
    <div className="min-h-screen bg-slate-50">
      <Sidebar 
        currentRole={currentUser.role} 
        activeTab={activeTab} 
        setActiveTab={setActiveTab} 
        onLogout={handleLogout} 
      />
      <main className="pl-64 min-h-screen transition-all">
        <div className="p-10 max-w-[1400px] mx-auto">
          {renderContent()}
        </div>
      </main>
    </div>
  );
};

export default App;

