               ))}
             </div>

             {showUserModal && (
               <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-sm z-[100] flex items-center justify-center p-4">
                 <div className="bg-white w-full max-w-md rounded-3xl p-8 shadow-2xl animate-in zoom-in duration-200">
                    <div className="flex justify-between items-center mb-6">
                      <h3 className="text-2xl font-bold text-slate-900">Add New User</h3>
                      <button onClick={() => setShowUserModal(false)} className="text-slate-400 hover:text-slate-600"><i className="fa-solid fa-xmark text-xl"></i></button>
                    </div>
                    <form onSubmit={handleCreateUser} className="space-y-4">
                      <div className="space-y-1">
                        <label className="text-xs font-bold text-slate-500 uppercase">Username</label>
                        <input name="username" required className="w-full border border-slate-200 p-3 rounded-xl focus:ring-2 focus:ring-emerald-500 outline-none" placeholder="Enter custom username..." />
                      </div>
                      <div className="space-y-1">
                        <label className="text-xs font-bold text-slate-500 uppercase">Assign Role</label>
                        <select name="role" required className="w-full border border-slate-200 p-3 rounded-xl focus:ring-2 focus:ring-emerald-500 outline-none">
                          <option value={UserRole.PROCUREMENT_MANAGER}>Procurement Manager</option>
                          <option value={UserRole.SUSTAINABILITY_MANAGER}>Sustainability Manager</option>
                          <option value={UserRole.ADMIN}>Administrator</option>
                        </select>
                      </div>
                      <div className="flex gap-3 mt-8">
                        <button type="button" onClick={() => setShowUserModal(false)} className="flex-1 px-4 py-3 rounded-xl border font-bold text-slate-500 hover:bg-slate-50">Cancel</button>
                        <button type="submit" className="flex-1 bg-emerald-600 text-white px-4 py-3 rounded-xl font-bold hover:bg-emerald-700 shadow-lg">Save User</button>
                      </div>
                    </form>
                 </div>
               </div>
             )}
          </div>
        )
      default:
        return <Dashboard suppliers={suppliers} materials={materials} procurement={procurement} energy={energy} />;
    }
  };

  if (!currentUser) {
    return (
      <div className="min-h-screen bg-slate-900 flex items-center justify-center p-4">
        <div className="bg-white w-full max-w-md rounded-3xl p-8 shadow-2xl animate-in zoom-in duration-300">
          <div className="text-center mb-8">
            <div className="w-16 h-16 bg-emerald-100 text-emerald-600 rounded-2xl flex items-center justify-center text-3xl mx-auto mb-4">
              <i className="fa-solid fa-leaf"></i>
            </div>
            <h1 className="text-3xl font-extrabold text-slate-900">Green ERP</h1>
            <p className="text-slate-500 mt-2 font-medium">Sustainability Decision Support</p>
          </div>

          <form onSubmit={handleLogin} className="space-y-6">
            <div className="space-y-2">
              <label className="text-xs font-bold text-slate-500 uppercase tracking-widest ml-1">Username</label>
              <input 
                type="text" 
                className="w-full bg-slate-50 border border-slate-100 p-4 rounded-xl focus:ring-2 focus:ring-emerald-500 outline-none transition-all font-medium uppercase" 
                placeholder="e.g. admin"
                value={loginInput.username}
                onChange={e => setLoginInput({...loginInput, username: e.target.value})}
                required
              />
            </div>

            <div className="space-y-2">
              <label className="text-xs font-bold text-slate-500 uppercase tracking-widest ml-1">Select Role</label>
              <div className="grid grid-cols-1 gap-2">
                {[UserRole.ADMIN, UserRole.PROCUREMENT_MANAGER, UserRole.SUSTAINABILITY_MANAGER].map(role => (
                  <button
                    key={role}
                    type="button"
                    onClick={() => setLoginInput({...loginInput, role})}
                    className={`text-left px-4 py-3 rounded-xl border text-sm font-semibold transition-all ${
                      loginInput.role === role 
                        ? 'border-emerald-500 bg-emerald-50 text-emerald-700 shadow-sm' 
                        : 'border-slate-100 bg-slate-50 text-slate-400 hover:border-emerald-200'
                    }`}
                  >
                    <i className={`fa-solid ${role === UserRole.ADMIN ? 'fa-user-shield' : role === UserRole.PROCUREMENT_MANAGER ? 'fa-truck-ramp-box' : 'fa-seedling'} mr-2`}></i>
                    {role.replace('_', ' ')}
                  </button>
                ))}
              </div>
            </div>

            <button type="submit" className="w-full bg-slate-900 text-white py-4 rounded-xl font-bold text-lg hover:bg-emerald-600 transition-all shadow-xl hover:shadow-emerald-200/50 flex items-center justify-center gap-2">
              Launch Portal
              <i className="fa-solid fa-arrow-right"></i>
            </button>
          </form>

          <div className="mt-8 pt-6 border-t border-slate-100 text-center">
             <p className="text-xs text-slate-400">© 2024 Green ERP System - MCA Final Year Project</p>
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-slate-50">
      <Sidebar 
        currentRole={currentUser.role} 
        activeTab={activeTab} 
        setActiveTab={setActiveTab} 
        onLogout={handleLogout} 
      />
      <main className="pl-64 min-h-screen transition-all">
        <div className="p-10 max-w-[1400px] mx-auto">
          {renderContent()}
        </div>
      </main>
    </div>
  );
};

export default App;

import React, { useMemo, useState } from 'react';
import { Supplier, Material, ProcurementRecord, Recommendation } from '../types';

interface RecommendationEngineProps {
  suppliers: Supplier[];
  materials: Material[];
  procurement: ProcurementRecord[];
}

const RecommendationEngine: React.FC<RecommendationEngineProps> = ({ suppliers, materials, procurement }) => {
  const [applying, setApplying] = useState<string | null>(null);

  const recommendations = useMemo(() => {
    const recs: Recommendation[] = [];

    // 1. Material Switch Logic
    const highImpactMaterials = materials.filter(m => m.carbonFactor > 10);
    highImpactMaterials.forEach(m => {
      const alternative = materials.find(alt => alt.category === m.category && alt.carbonFactor < m.carbonFactor);
      if (alternative) {
        recs.push({
          id: `rec-m-${m.id}`,
          type: 'MATERIAL',
          title: `Switch Material: ${m.name}`,
          description: `Consider replacing '${m.name}' with '${alternative.name}' to reduce footprint by ${Math.round((1 - alternative.carbonFactor/m.carbonFactor) * 100)}%.`,
          impact: 'High'
        });
      }
    });

    // 2. Supplier Shift Logic (Better Alternative)
    const activeSupplierIds = new Set(procurement.map(p => p.supplierId));
    suppliers.filter(s => activeSupplierIds.has(s.id) && s.sustainabilityScore < 60).forEach(s => {
      const betterSupplier = suppliers.find(alt => alt.category === s.category && alt.sustainabilityScore > 80);
      if (betterSupplier) {
        recs.push({
          id: `rec-s-${s.id}`,
          type: 'SUPPLIER',
          title: `Supplier Shift: ${s.name}`,
          description: `Switching to '${betterSupplier.name}' (Score: ${betterSupplier.sustainabilityScore}) improves your rating.`,
          impact: 'Medium'
        });
      }
    });

    // 3. NEW: Flag suppliers with high carbon intensity (low efficiency) and low scores
    // Logic: Score < 50 AND carbonEfficiency > 30 (high emissions per $)
    suppliers.filter(s => s.sustainabilityScore < 50 && s.carbonEfficiency > 30).forEach(s => {
      recs.push({
        id: `rec-audit-${s.id}`,
        type: 'SUPPLIER',
        title: `Audit Required: ${s.name}`,
        description: `Flagged for high carbon intensity (${s.carbonEfficiency} kg/k$) and low score (${s.sustainabilityScore}/100). A mandatory practice review is recommended.`,
        impact: 'High'
      });
    });

    // 4. Optimization Logic
    if (procurement.length > 5) {
      recs.push({
        id: 'rec-opt-1',
        type: 'OPTIMIZATION',
        title: 'Route Consolidation',
        description: 'Optimize shipment frequency to lower Scope 3 transportation emissions.',
        impact: 'Low'
      });
    }

    return recs;
  }, [suppliers, materials, procurement]);

  const handleApply = (id: string) => {
    setApplying(id);
    setTimeout(() => {
      setApplying(null);
      alert("Simulation: This strategy has been added to the procurement policy for future orders.");
    }, 1200);
  };

  return (
    <div className="space-y-6 animate-in slide-in-from-bottom duration-500">
      <header>
        <h2 className="text-3xl font-bold text-slate-900 tracking-tight">Smart Insights</h2>
        <p className="text-slate-500 mt-1">Automated decision support based on procurement logic.</p>
      </header>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
        {recommendations.length > 0 ? recommendations.map(rec => (
          <div key={rec.id} className="bg-white rounded-2xl border p-6 shadow-sm flex flex-col group relative">
            <div className={`absolute top-0 right-0 p-4 opacity-5 group-hover:opacity-20 transition-opacity`}>
              <i className={`fa-solid ${rec.type === 'MATERIAL' ? 'fa-box' : 'fa-truck'} text-6xl`}></i>
            </div>
            <div className="flex items-center justify-between mb-4">
              <span className={`px-2 py-0.5 rounded-full text-[10px] font-bold uppercase ${rec.impact === 'High' ? 'bg-rose-100 text-rose-600' : rec.impact === 'Medium' ? 'bg-blue-100 text-blue-600' : 'bg-slate-100 text-slate-600'}`}>
                {rec.impact} Impact
              </span>
            </div>
            <h3 className="text-lg font-bold text-slate-900 mb-2">{rec.title}</h3>
            <p className="text-slate-500 text-sm leading-relaxed mb-6">{rec.description}</p>
            <button 
              onClick={() => handleApply(rec.id)}
              disabled={!!applying}
              className="mt-auto w-full bg-slate-50 text-emerald-600 py-2.5 rounded-xl font-bold text-sm hover:bg-emerald-600 hover:text-white transition-all flex items-center justify-center gap-2"
            >
              {applying === rec.id ? <i className="fa-solid fa-spinner animate-spin"></i> : 'Apply Strategy'}
            </button>
          </div>
        )) : (
            <div className="col-span-full py-20 text-center bg-white rounded-2xl border border-dashed border-slate-300">
                <i className="fa-solid fa-wand-magic-sparkles text-4xl text-slate-200 mb-4"></i>
                <p className="text-slate-400 font-medium">No new insights available based on current data.</p>
            </div>
        )}
      </div>

      <div className="bg-emerald-900 rounded-3xl p-8 text-white relative overflow-hidden mt-10">
        <div className="relative z-10 max-w-xl">
          <h3 className="text-2xl font-bold mb-3">Rule-Based Efficiency</h3>
          <p className="text-emerald-100 opacity-80">This engine maps materials and suppliers to environmental benchmarks. High-emission sources and low-scoring vendors are flagged automatically to support your sustainability goals.</p>
        </div>
      </div>
    </div>
  );
};

export default RecommendationEngine;

import React, { useState, useMemo } from 'react';
import { UserRole, User, Supplier, Material, ProcurementRecord, EnergyRecord } from './types';
import { INITIAL_USERS, INITIAL_SUPPLIERS, INITIAL_MATERIALS, INITIAL_PROCUREMENT, INITIAL_ENERGY } from './constants';
import Sidebar from './components/Sidebar';
import Dashboard from './views/Dashboard';
import MasterData from './views/MasterData';
import DataManagement from './views/DataManagement';
import RecommendationEngine from './views/RecommendationEngine';

const App: React.FC = () => {
  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [activeTab, setActiveTab] = useState('dashboard');
  const [isGeneratingReport, setIsGeneratingReport] = useState(false);
  const [showUserModal, setShowUserModal] = useState(false);

  // App State
  const [suppliers, setSuppliers] = useState<Supplier[]>(INITIAL_SUPPLIERS);
  const [materials, setMaterials] = useState<Material[]>(INITIAL_MATERIALS);
  const [procurement, setProcurement] = useState<ProcurementRecord[]>(INITIAL_PROCUREMENT);
  const [energy, setEnergy] = useState<EnergyRecord[]>(INITIAL_ENERGY);
  const [users, setUsers] = useState<User[]>(INITIAL_USERS);

  // Auth logic
  const [loginInput, setLoginInput] = useState({ username: '', role: UserRole.ADMIN });

  const handleLogin = (e: React.FormEvent) => {
    e.preventDefault();
    const enteredUsername = loginInput.username.toLowerCase();

    // Check if user exists first
    const userExists = users.some(u => u.username.toLowerCase() === enteredUsername);

    if (!userExists) {
      alert(`Login Failed: The username "${loginInput.username}" does not exist in our system.`);
      return;
    }

    const validUserWithRole = users.find(u => u.username.toLowerCase() === enteredUsername && u.role === loginInput.role);

    if (validUserWithRole) {
      setCurrentUser(validUserWithRole);
    } else {
      alert(`Login Failed: The user "${loginInput.username}" exists but is not assigned the "${loginInput.role.replace('_', ' ')}" role.`);
    }
  };

  const handleLogout = () => {
    setCurrentUser(null);
    setActiveTab('dashboard');
  };

  // Data Handlers
  const addProcurement = (p: Omit<ProcurementRecord, 'id'>) => {
    setProcurement(prev => [{ ...p, id: `p-${Date.now()}` }, ...prev]);
  };

  const addEnergy = (e: Omit<EnergyRecord, 'id'>) => {
    setEnergy(prev => [{ ...e, id: `e-${Date.now()}` }, ...prev]);
  };

  const manageSupplier = (supplier: Supplier, mode: 'add' | 'edit' | 'delete') => {
    if (mode === 'add') setSuppliers(prev => [...prev, supplier]);
    if (mode === 'edit') setSuppliers(prev => prev.map(s => s.id === supplier.id ? supplier : s));
    if (mode === 'delete') setSuppliers(prev => prev.filter(s => s.id !== supplier.id));
  };

  const manageMaterial = (material: Material, mode: 'add' | 'edit' | 'delete') => {
    if (mode === 'add') setMaterials(prev => [...prev, material]);
    if (mode === 'edit') setMaterials(prev => prev.map(m => m.id === material.id ? material : m));
    if (mode === 'delete') setMaterials(prev => prev.filter(m => m.id !== material.id));
  };

  const handleCreateUser = (e: React.FormEvent) => {
    e.preventDefault();
    const formData = new FormData(e.currentTarget as HTMLFormElement);
    const username = formData.get('username') as string;
    const role = formData.get('role') as UserRole;

    if (!username.trim()) return alert("Username is required");
    if (users.some(u => u.username.toLowerCase() === username.toLowerCase())) {
        return alert("Username already exists!");
    }

    const newUser: User = {
      id: `u-${Date.now()}`,
      username: username,
      role: role
    };

    setUsers(prev => [...prev, newUser]);
    setShowUserModal(false);
  };

  const deleteUser = (user: User) => {
    if (user.id === currentUser?.id) return alert("Cannot delete currently logged-in user.");
    if (confirm(`Are you sure you want to delete user "${user.username}"?`)) {
      setUsers(prev => prev.filter(u => u.id !== user.id));
    }
  };

  const handleGenerateReport = () => {
    setIsGeneratingReport(true);
    setTimeout(() => {
      const energyCarbon = energy.reduce((sum, e) => sum + e.carbonEquivalent, 0);
      const materialCarbon = procurement.reduce((sum, p) => {
        const mat = materials.find(m => m.id === p.materialId);
        return sum + (p.quantity * (mat?.carbonFactor || 0));
      }, 0);

      const reportData = [
        ["Annual Sustainability Report", "2023"],
        ["Generated By", currentUser?.username || "System"],
        [""],
        ["KPI SUMMARY"],
        ["Total Energy Carbon Footprint", energyCarbon + " kg CO2e"],
        ["Total Procurement Carbon Footprint", materialCarbon + " kg CO2e"],
        ["Total Cumulative Footprint", (energyCarbon + materialCarbon) + " kg CO2e"],
        [""],
        ["ENERGY CONSUMPTION DETAILS"],
        ["Source", "Date", "Amount", "CO2 Equivalent"],
        ...energy.map(e => [e.source, e.date, e.amount + " " + e.unit, e.carbonEquivalent + " kg"]),
        [""],
        ["PROCUREMENT LOGS"],
        ["Date", "Material", "Quantity", "Total Cost"],
        ...procurement.map(p => {
          const m = materials.find(mat => mat.id === p.materialId);
          return [p.date, m?.name || "Unknown", p.quantity, "$" + p.totalCost];
        })
      ];

      const csvContent = reportData.map(e => e.join(",")).join("\n");
      const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' });
      const link = document.createElement("a");
      const url = URL.createObjectURL(blob);
      link.setAttribute("href", url);
      link.setAttribute("download", `annual_sustainability_report_${new Date().getFullYear()}.csv`);
      link.style.visibility = 'hidden';
      document.body.appendChild(link);
      link.click();
      document.body.removeChild(link);

      setIsGeneratingReport(false);
      alert('Sustainability Report generated and downloaded successfully!');
    }, 1500);
  };

  const renderContent = () => {
    if (!currentUser) return null;

    switch(activeTab) {
      case 'dashboard':
        return <Dashboard suppliers={suppliers} materials={materials} procurement={procurement} energy={energy} />;
      case 'master-data':
        return <MasterData suppliers={suppliers} materials={materials} onSupplierAction={manageSupplier} onMaterialAction={manageMaterial} />;
      case 'data-management':
        return (
          <DataManagement 
            materials={materials} 
            suppliers={suppliers} 
            procurement={procurement}
            energy={energy}
            currentRole={currentUser.role}
            onAddProcurement={addProcurement} 
            onAddEnergy={addEnergy} 
          />
        );
      case 'recommendations':
        return <RecommendationEngine suppliers={suppliers} materials={materials} procurement={procurement} />;
      case 'reports':
        return (
          <div className="flex flex-col items-center justify-center py-24 space-y-6">
             <div className="w-24 h-24 bg-white rounded-full flex items-center justify-center shadow-xl border border-slate-100 mb-2">
                <i className={`fa-solid ${isGeneratingReport ? 'fa-spinner animate-spin text-emerald-500' : 'fa-file-pdf text-slate-300'} text-5xl`}></i>
             </div>
             <div className="text-center">
                <h3 className="text-2xl font-bold text-slate-900">Sustainability Reporting</h3>
                <p className="text-slate-500 text-center max-w-md mt-2">Generate comprehensive GHG Protocol-aligned carbon reports and supplier performance summaries in one click.</p>
             </div>
             <button 
                onClick={handleGenerateReport}
                disabled={isGeneratingReport}
                className={`bg-emerald-600 text-white px-8 py-3 rounded-xl font-bold hover:bg-emerald-700 transition-all shadow-lg flex items-center gap-2 ${isGeneratingReport ? 'opacity-70 cursor-wait' : ''}`}
             >
               {isGeneratingReport ? 'Compiling Dataset...' : 'Generate Annual Report'}
               {!isGeneratingReport && <i className="fa-solid fa-bolt"></i>}
             </button>
          </div>
        );
      case 'users':
        return (
          <div className="bg-white p-8 rounded-2xl border shadow-sm max-w-4xl mx-auto">
             <div className="flex justify-between items-center mb-8">
                <div>
                  <h3 className="text-2xl font-bold text-slate-900 tracking-tight">System Users</h3>
                  <p className="text-slate-500 text-sm mt-1">Manage platform access and assign roles.</p>
                </div>
                <button 
                  onClick={() => setShowUserModal(true)}
                  className="bg-slate-900 text-white px-5 py-2.5 rounded-xl text-sm font-bold hover:bg-slate-800 transition-all shadow-lg"
                >
                  <i className="fa-solid fa-plus mr-2"></i> Add New User
                </button>
             </div>
             <div className="divide-y border-t">
               {users.map(u => (
                 <div key={u.id} className="py-5 flex justify-between items-center group transition-colors hover:bg-slate-50 px-2 rounded-lg">
                    <div className="flex items-center gap-4">
                      <div className="w-12 h-12 rounded-full bg-slate-100 flex items-center justify-center font-bold text-slate-400 group-hover:bg-emerald-100 group-hover:text-emerald-600 transition-colors">
                        {u.username.charAt(0).toUpperCase()}
                      </div>
                      <div>
                        <p className="font-bold text-slate-900">{u.username}</p>
                        <p className="text-xs text-slate-400 font-bold tracking-wide uppercase">{u.role.replace('_', ' ')}</p>
                      </div>
                    </div>
                    <div className="flex items-center gap-3">
                      <span className="px-3 py-1 bg-emerald-50 text-emerald-600 rounded-full text-[10px] font-bold">ACTIVE</span>
                      <button 
                        onClick={() => deleteUser(u)}
                        className="text-slate-300 hover:text-rose-500 p-2 transition-colors"
                        title="Remove User"
                      >
                        <i className="fa-solid fa-trash-can"></i>
                      </button>
                    </div>
                 </div>
               ))}
             </div>

             {showUserModal && (
               <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-sm z-[100] flex items-center justify-center p-4">
                 <div className="bg-white w-full max-w-md rounded-3xl p-8 shadow-2xl animate-in zoom-in duration-200">
                    <div className="flex justify-between items-center mb-6">
                      <h3 className="text-2xl font-bold text-slate-900">Add New User</h3>
                      <button onClick={() => setShowUserModal(false)} className="text-slate-400 hover:text-slate-600"><i className="fa-solid fa-xmark text-xl"></i></button>
                    </div>
                    <form onSubmit={handleCreateUser} className="space-y-4">
                      <div className="space-y-1">
                        <label className="text-xs font-bold text-slate-500 uppercase">Username</label>
                        <input name="username" required className="w-full border border-slate-200 p-3 rounded-xl focus:ring-2 focus:ring-emerald-500 outline-none" placeholder="Enter custom username..." />
                      </div>
                      <div className="space-y-1">
                        <label className="text-xs font-bold text-slate-500 uppercase">Assign Role</label>
                        <select name="role" required className="w-full border border-slate-200 p-3 rounded-xl focus:ring-2 focus:ring-emerald-500 outline-none">
                          <option value={UserRole.PROCUREMENT_MANAGER}>Procurement Manager</option>
                          <option value={UserRole.SUSTAINABILITY_MANAGER}>Sustainability Manager</option>
                          <option value={UserRole.ADMIN}>Administrator</option>
                        </select>
                      </div>
                      <div className="flex gap-3 mt-8">
                        <button type="button" onClick={() => setShowUserModal(false)} className="flex-1 px-4 py-3 rounded-xl border font-bold text-slate-500 hover:bg-slate-50">Cancel</button>
                        <button type="submit" className="flex-1 bg-emerald-600 text-white px-4 py-3 rounded-xl font-bold hover:bg-emerald-700 shadow-lg">Save User</button>
                      </div>
                    </form>
                 </div>
               </div>
             )}
          </div>
        )
      default:
        return <Dashboard suppliers={suppliers} materials={materials} procurement={procurement} energy={energy} />;
    }
  };

  if (!currentUser) {
    return (
      <div className="min-h-screen bg-slate-900 flex items-center justify-center p-4">
        <div className="bg-white w-full max-w-md rounded-3xl p-8 shadow-2xl animate-in zoom-in duration-300">
          <div className="text-center mb-8">
            <div className="w-16 h-16 bg-emerald-100 text-emerald-600 rounded-2xl flex items-center justify-center text-3xl mx-auto mb-4">
              <i className="fa-solid fa-leaf"></i>
            </div>
            <h1 className="text-3xl font-extrabold text-slate-900">Green ERP</h1>
            <p className="text-slate-500 mt-2 font-medium">Sustainability Decision Support</p>
          </div>

          <form onSubmit={handleLogin} className="space-y-6">
            <div className="space-y-2">
              <label className="text-xs font-bold text-slate-500 uppercase tracking-widest ml-1">Username</label>
              <input 
                type="text" 
                className="w-full bg-slate-50 border border-slate-100 p-4 rounded-xl focus:ring-2 focus:ring-emerald-500 outline-none transition-all font-medium" 
                placeholder="e.g. admin"
                value={loginInput.username}
                onChange={e => setLoginInput({...loginInput, username: e.target.value})}
                required
              />
            </div>

            <div className="space-y-2">
              <label className="text-xs font-bold text-slate-500 uppercase tracking-widest ml-1">Select Role</label>
              <div className="grid grid-cols-1 gap-2">
                {[UserRole.ADMIN, UserRole.PROCUREMENT_MANAGER, UserRole.SUSTAINABILITY_MANAGER].map(role => (
                  <button
                    key={role}
                    type="button"
                    onClick={() => setLoginInput({...loginInput, role})}
                    className={`text-left px-4 py-3 rounded-xl border text-sm font-semibold transition-all ${
                      loginInput.role === role 
                        ? 'border-emerald-500 bg-emerald-50 text-emerald-700 shadow-sm' 
                        : 'border-slate-100 bg-slate-50 text-slate-400 hover:border-emerald-200'
                    }`}
                  >
                    <i className={`fa-solid ${role === UserRole.ADMIN ? 'fa-user-shield' : role === UserRole.PROCUREMENT_MANAGER ? 'fa-truck-ramp-box' : 'fa-seedling'} mr-2`}></i>
                    {role.replace('_', ' ')}
                  </button>
                ))}
              </div>
            </div>

            <button type="submit" className="w-full bg-slate-900 text-white py-4 rounded-xl font-bold text-lg hover:bg-emerald-600 transition-all shadow-xl hover:shadow-emerald-200/50 flex items-center justify-center gap-2">
              Launch Portal
              <i className="fa-solid fa-arrow-right"></i>
            </button>
          </form>

          <div className="mt-8 pt-6 border-t border-slate-100 text-center">
             <p className="text-xs text-slate-400">© 2024 Green ERP System - MCA Final Year Project</p>
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-slate-50">
      <Sidebar 
        currentRole={currentUser.role} 
        activeTab={activeTab} 
        setActiveTab={setActiveTab} 
        onLogout={handleLogout} 
      />
      <main className="pl-64 min-h-screen transition-all">
        <div className="p-10 max-w-[1400px] mx-auto">
          {renderContent()}
        </div>
      </main>
    </div>
  );
};

