    if (mode === 'delete') {
      await api.deleteSupplier(supplier.id);
      setSuppliers(prev => prev.filter(s => s.id !== supplier.id));
    } else {
      await api.saveSupplier(supplier, mode);
      if (mode === 'add') setSuppliers(prev => [...prev, supplier]);
      else setSuppliers(prev => prev.map(s => s.id === supplier.id ? supplier : s));
    }
  };

  const manageMaterial = async (material: Material, mode: 'add' | 'edit' | 'delete') => {
    if (mode === 'delete') {
      await api.deleteMaterial(material.id);
      setMaterials(prev => prev.filter(m => m.id !== material.id));
    } else {
      await api.saveMaterial(material, mode);
      if (mode === 'add') setMaterials(prev => [...prev, material]);
      else setMaterials(prev => prev.map(m => m.id === material.id ? material : m));
    }
  };

  const handleCreateUser = async (e: React.FormEvent) => {
    e.preventDefault();
    const formData = new FormData(e.currentTarget as HTMLFormElement);
    const username = (formData.get('username') as string).trim();
    const role = formData.get('role') as UserRole;

    if (!username) return alert("User name is required.");
    if (await api.checkUserExists(username)) return alert("Username taken.");

    const newUser: User = { id: `u-${Date.now()}`, username, role };
    await api.createUser(newUser);
    setUsers(prev => [...prev, newUser]);
    setShowUserModal(false);
  };

  const deleteUser = async (user: User) => {
    if (user.id === currentUser?.id) return alert("Cannot delete yourself.");
    if (confirm(`Remove "${user.username}"?`)) {
      await api.deleteUser(user.id);
      setUsers(prev => prev.filter(u => u.id !== user.id));
    }
  };

  const renderContent = () => {
    if (!currentUser) return null;
    switch(activeTab) {
      case 'dashboard':
        return <Dashboard suppliers={suppliers} materials={materials} procurement={procurement} energy={energy} currentUser={currentUser} />;
      case 'master-data':
        return <MasterData suppliers={suppliers} materials={materials} onSupplierAction={manageSupplier} onMaterialAction={manageMaterial} />;
      case 'data-management':
        return <DataManagement materials={materials} suppliers={suppliers} procurement={procurement} energy={energy} currentRole={currentUser.role} onAddProcurement={addProcurement} onAddEnergy={addEnergy} />;
      case 'recommendations':
        return <RecommendationEngine suppliers={suppliers} materials={materials} procurement={procurement} />;
      case 'reports':
        return (
          <div className="flex flex-col items-center justify-center py-24 text-center">
             <div className="w-20 h-20 bg-emerald-900/50 text-emerald-400 rounded-full flex items-center justify-center mb-6 border border-emerald-500/30">
                <i className={`fa-solid ${isGeneratingReport ? 'fa-spinner animate-spin' : 'fa-file-pdf'} text-3xl`}></i>
             </div>
             <h3 className="text-2xl font-bold text-white">Generate Sustainability Report</h3>
             <p className="text-slate-400 mt-2 max-w-sm">Compile all environmental KPIs and procurement analytics into a downloadable document.</p>
             <button onClick={() => { setIsGeneratingReport(true); setTimeout(() => { setIsGeneratingReport(false); alert("Report downloaded!"); }, 1500); }} disabled={isGeneratingReport} className="mt-8 bg-emerald-600 text-white px-8 py-3 rounded-xl font-bold shadow-lg hover:bg-emerald-500 transition-all disabled:opacity-50">
               {isGeneratingReport ? 'Processing...' : 'Download Report'}
             </button>
          </div>
        );
      case 'users':
        return (
          <div className="bg-slate-900 p-8 rounded-2xl border border-slate-800 shadow-xl max-w-4xl mx-auto">
             <div className="flex justify-between items-center mb-8">
                <div>
                  <h3 className="text-2xl font-bold text-white">Manage Personnel</h3>
                  <p className="text-slate-400 text-sm">Create and manage access for system users.</p>
                </div>
                <button onClick={() => setShowUserModal(true)} className="bg-emerald-600 text-white px-5 py-2.5 rounded-xl font-bold hover:bg-emerald-500 transition-all shadow-lg">Add User</button>
             </div>
             <div className="divide-y divide-slate-800 border-t border-slate-800">
               {users.map(u => (
                 <div key={u.id} className="py-4 flex justify-between items-center px-2">
                    <div className="flex items-center gap-3">
                      <div className="w-10 h-10 rounded-full bg-slate-800 border border-slate-700 flex items-center justify-center font-bold text-emerald-400">{u.username.charAt(0).toUpperCase()}</div>
                      <div>
                        <p className="font-bold text-white">{u.username}</p>
                        <p className="text-xs text-slate-500 font-bold uppercase">{u.role.replace('_', ' ')}</p>
                      </div>
                    </div>
                    <button onClick={() => deleteUser(u)} className="text-slate-500 hover:text-rose-500 p-2 transition-colors"><i className="fa-solid fa-trash"></i></button>
                 </div>
               ))}
             </div>
             {showUserModal && (
               <div className="fixed inset-0 bg-slate-950/80 backdrop-blur-sm z-[100] flex items-center justify-center p-4">
                 <div className="bg-slate-900 w-full max-w-md rounded-3xl p-8 shadow-2xl border border-slate-800 animate-in zoom-in duration-200">
                    <h3 className="text-2xl font-bold mb-6 text-white">Create System User</h3>
                    <form onSubmit={handleCreateUser} className="space-y-4">
                      <div className="space-y-1">
                        <label className="text-xs font-bold text-slate-400 uppercase">User Name</label>
                        <input name="username" required className="w-full bg-slate-800 border border-slate-700 p-3 rounded-xl outline-none text-white focus:ring-2 focus:ring-emerald-500 placeholder-slate-500" placeholder="e.g. Rahul" />
                      </div>
                      <div className="space-y-1">
                        <label className="text-xs font-bold text-slate-400 uppercase">System Role</label>
                        <select name="role" required className="w-full bg-slate-800 border border-slate-700 p-3 rounded-xl outline-none text-white focus:ring-2 focus:ring-emerald-500">
                          <option value={UserRole.PROCUREMENT_MANAGER}>Procurement Manager</option>
                          <option value={UserRole.SUSTAINABILITY_MANAGER}>Sustainability Manager</option>
                          <option value={UserRole.ADMIN}>Administrator</option>
                        </select>
                      </div>
                      <div className="flex gap-3 mt-8">
                        <button type="button" onClick={() => setShowUserModal(false)} className="flex-1 py-3 rounded-xl border border-slate-700 text-slate-300 font-bold hover:bg-slate-800">Cancel</button>
                        <button type="submit" className="flex-1 bg-emerald-600 text-white py-3 rounded-xl font-bold hover:bg-emerald-500">Create User</button>
                      </div>
                    </form>
                 </div>
               </div>
             )}
          </div>
        );
      default: return null;
    }
  };

  if (!currentUser) {
    return (
      <div className="min-h-screen bg-slate-950 flex items-center justify-center p-4">
        <div className="bg-slate-900 w-full max-w-md rounded-3xl p-8 shadow-2xl border border-slate-800 animate-in zoom-in duration-300">
          <div className="text-center mb-8">
            <div className="w-16 h-16 bg-emerald-900/50 text-emerald-400 border border-emerald-500/20 rounded-2xl flex items-center justify-center text-3xl mx-auto mb-4">
              <i className="fa-solid fa-leaf"></i>
            </div>
            <h1 className="text-3xl font-extrabold text-white tracking-tight">Green ERP</h1>
            <p className="text-slate-400 mt-2 font-medium">Sustainability Decision Support</p>
          </div>

          <form onSubmit={handleLogin} className="space-y-5">
            <div className="space-y-2">
              <label className="text-xs font-bold text-slate-400 uppercase tracking-widest ml-1">Username</label>
              <input 
                name="username"
                type="text" 
                disabled={isSyncing}
                className={`w-full bg-slate-800 border p-4 rounded-xl outline-none transition-all font-medium text-white placeholder-slate-500 ${loginError ? 'border-rose-500 ring-2 ring-rose-500/10' : 'border-slate-700 focus:ring-2 focus:ring-emerald-500'}`}
                placeholder="Enter registered name"
              />
              {loginError && <p className="text-rose-500 text-xs font-bold ml-1 animate-pulse"><i className="fa-solid fa-circle-exclamation mr-1"></i> {loginError}</p>}
            </div>

            <div className="space-y-2">
              <label className="text-xs font-bold text-slate-400 uppercase tracking-widest ml-1">Select Role</label>
              <select name="role" disabled={isSyncing} className="w-full bg-slate-800 border border-slate-700 p-4 rounded-xl outline-none font-medium text-white focus:ring-2 focus:ring-emerald-500">
                <option value={UserRole.ADMIN}>Administrator</option>
                <option value={UserRole.PROCUREMENT_MANAGER}>Procurement Manager</option>
                <option value={UserRole.SUSTAINABILITY_MANAGER}>Sustainability Manager</option>
              </select>
            </div>

            <button type="submit" disabled={isSyncing} className="w-full bg-emerald-600 text-white py-4 rounded-xl font-bold text-lg hover:bg-emerald-500 transition-all shadow-xl flex items-center justify-center gap-2 disabled:opacity-50">
              {isSyncing ? <i className="fa-solid fa-spinner animate-spin"></i> : 'Sign In'} <i className="fa-solid fa-arrow-right"></i>
            </button>
          </form>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-slate-950 text-slate-100">
      {isSyncing && (
        <div className="fixed top-0 left-0 w-full h-1 z-[200]">
          <div className="h-full bg-emerald-500 animate-pulse"></div>
        </div>
      )}
      <Sidebar currentRole={currentUser.role} activeTab={activeTab} setActiveTab={setActiveTab} onLogout={handleLogout} />
      <main className="pl-64 min-h-screen">
        <div className="p-10 max-w-[1400px] mx-auto">{renderContent()}</div>
      </main>
    </div>
  );
};

export default App;

import React from 'react';

interface KPICardProps {
  title: string;
  value: string | number;
  unit?: string;
  icon: string;
  trend?: {
    value: number;
    isUp: boolean;
  };
  color: 'emerald' | 'blue' | 'amber' | 'rose' | 'indigo';
}

const KPICard: React.FC<KPICardProps> = ({ title, value, unit, icon, trend, color }) => {
  const iconColorMap = {
    emerald: 'bg-emerald-500',
    blue: 'bg-blue-500',
    amber: 'bg-amber-500',
    rose: 'bg-rose-500',
    indigo: 'bg-indigo-500',
  };

  return (
    <div className="bg-slate-900 rounded-2xl p-6 border border-slate-800 shadow-xl transition-transform hover:scale-[1.02] cursor-default">
      <div className="flex items-start justify-between mb-4">
        <div className={`p-3 rounded-xl text-white shadow-lg ${iconColorMap[color]}`}>
          <i className={`fa-solid ${icon} text-lg`}></i>
        </div>
        {trend && (
          <span className={`text-xs font-bold flex items-center gap-1 ${trend.isUp ? 'text-rose-400' : 'text-emerald-400'}`}>
            <i className={`fa-solid ${trend.isUp ? 'fa-arrow-trend-up' : 'fa-arrow-trend-down'}`}></i>
            {Math.abs(trend.value)}%
          </span>
        )}
      </div>
      <p className="text-slate-400 text-sm font-medium">{title}</p>
      <div className="flex items-baseline gap-1 mt-1">
        <h3 className="text-2xl font-bold text-white">{value}</h3>
        {unit && <span className="text-slate-500 text-sm font-medium ml-1">{unit}</span>}
      </div>
    </div>
  );
};

export default KPICard;

import React, { useMemo, useState } from 'react';
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, AreaChart, Area, Cell, PieChart, Pie } from 'recharts';
import { Supplier, Material, ProcurementRecord, EnergyRecord, User } from '../types';
import KPICard from '../components/KPICard';

interface DashboardProps {
  suppliers: Supplier[];
  materials: Material[];
  procurement: ProcurementRecord[];
  energy: EnergyRecord[];
  currentUser: User;
}

const Dashboard: React.FC<DashboardProps> = ({ suppliers, materials, procurement, energy, currentUser }) => {
  const [isExporting, setIsExporting] = useState(false);

  const stats = useMemo(() => {
    const energyCarbon = energy.reduce((sum, e) => sum + e.carbonEquivalent, 0);
    const materialCarbon = procurement.reduce((sum, p) => {
      const mat = materials.find(m => m.id === p.materialId);
      return sum + (p.quantity * (mat?.carbonFactor || 0));
    }, 0);
    const totalCarbon = energyCarbon + materialCarbon;
    const avgSupplierScore = suppliers.length > 0 ? Math.round(suppliers.reduce((sum, s) => sum + s.sustainabilityScore, 0) / suppliers.length) : 0;
    const totalSpend = procurement.reduce((sum, p) => sum + p.totalCost, 0);
    const totalQty = procurement.reduce((sum, p) => sum + p.quantity, 0);
    const avgRecyclability = totalQty > 0 ? Math.round(procurement.reduce((sum, p) => sum + (p.quantity * (materials.find(m => m.id === p.materialId)?.recyclabilityRate || 0)), 0) / totalQty) : 0;

    return { totalCarbon, avgSupplierScore, totalSpend, avgRecyclability, energyCarbon, materialCarbon };
  }, [suppliers, materials, procurement, energy]);

  const handleExport = () => {
    setIsExporting(true);
    setTimeout(() => setIsExporting(false), 800);
  };

  const trendData = [
    { month: 'Jul', co2: 2400 },
    { month: 'Aug', co2: 2100 },
    { month: 'Sep', co2: 2800 },
    { month: 'Oct', co2: Math.round(stats.totalCarbon) || 2500 },
  ];

  const emissionBySourceData = [
    { name: 'Energy', value: stats.energyCarbon, color: '#10b981' },
    { name: 'Procurement', value: stats.materialCarbon, color: '#3b82f6' },
  ];

  return (
    <div className="space-y-8 animate-in fade-in duration-500">
      <header className="flex justify-between items-center">
        <div>
          <div className="flex items-center gap-3 mb-1">
            <h2 className="text-3xl font-bold text-white tracking-tight">Sustainability Overview</h2>
            <div className="px-3 py-1 bg-emerald-900/40 text-emerald-400 text-[10px] font-extrabold uppercase rounded-full border border-emerald-500/20 shadow-sm flex items-center gap-2">
              <i className="fa-solid fa-user-circle"></i>
              Session: {currentUser.username}
            </div>
          </div>
          <p className="text-slate-400 font-medium">Monitoring environmental impact across energy and procurement.</p>
        </div>
        <button onClick={handleExport} disabled={isExporting} className="bg-emerald-600 text-white px-5 py-2.5 rounded-xl font-bold shadow-lg hover:bg-emerald-500 transition-all disabled:opacity-50">
          <i className={`fa-solid ${isExporting ? 'fa-spinner animate-spin' : 'fa-download'} mr-2`}></i> {isExporting ? 'Exporting...' : 'Export Results'}
        </button>
      </header>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
        <KPICard title="Total Carbon" value={stats.totalCarbon.toLocaleString()} unit="kg CO2" icon="fa-cloud" color="rose" />
        <KPICard title="Avg Supplier Score" value={stats.avgSupplierScore} unit="/ 100" icon="fa-award" color="emerald" />
        <KPICard title="Total Material Spend" value={`$${(stats.totalSpend / 1000).toFixed(1)}k`} icon="fa-wallet" color="indigo" />
        <KPICard title="Avg Recyclability" value={stats.avgRecyclability} unit="%" icon="fa-recycle" color="amber" />
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
        <div className="lg:col-span-2 bg-slate-900 p-6 rounded-2xl border border-slate-800 shadow-xl">
          <h3 className="text-lg font-bold mb-6 text-white">Carbon Emission Trend</h3>
          <div className="h-[300px]">
            <ResponsiveContainer width="100%" height="100%">
              <AreaChart data={trendData}>
                <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#1e293b" />
                <XAxis dataKey="month" axisLine={false} tickLine={false} tick={{fill: '#94a3b8', fontSize: 12}} />
                <YAxis axisLine={false} tickLine={false} tick={{fill: '#94a3b8', fontSize: 12}} />
                <Tooltip 
                  contentStyle={{ backgroundColor: '#0f172a', borderRadius: '12px', border: '1px solid #1e293b', boxShadow: '0 25px 50px -12px rgb(0 0 0 / 0.5)', color: '#fff' }} 
                  itemStyle={{ color: '#10b981' }}
                />
                <Area type="monotone" dataKey="co2" stroke="#10b981" strokeWidth={3} fill="#10b981" fillOpacity={0.15} />
              </AreaChart>
            </ResponsiveContainer>
          </div>
        </div>
        <div className="bg-slate-900 p-6 rounded-2xl border border-slate-800 shadow-xl flex flex-col items-center">
          <h3 className="text-lg font-bold mb-6 text-white">Source Breakdown</h3>
          <div className="h-[250px] w-full relative">
            <ResponsiveContainer width="100%" height="100%">
              <PieChart>
                <Pie data={emissionBySourceData} cx="50%" cy="50%" innerRadius={60} outerRadius={80} paddingAngle={8} dataKey="value">
                  {emissionBySourceData.map((entry, index) => <Cell key={`cell-${index}`} fill={entry.color} />)}
                </Pie>
                <Tooltip 
                  contentStyle={{ backgroundColor: '#0f172a', borderRadius: '12px', border: '1px solid #1e293b' }}
                  itemStyle={{ color: '#fff' }}
                />
              </PieChart>
            </ResponsiveContainer>
            <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 text-center pointer-events-none">
                <p className="text-[10px] text-slate-500 font-bold uppercase tracking-widest">Total</p>
                <p className="text-xl font-bold text-white">{Math.round(stats.totalCarbon / 1000)}t</p>
            </div>
          </div>
          <div className="w-full space-y-3 mt-4">
             {emissionBySourceData.map(s => (
               <div key={s.name} className="flex justify-between items-center text-xs">
                 <span className="flex items-center gap-2 text-slate-300">
                    <div className="w-2 h-2 rounded-full" style={{backgroundColor: s.color}}></div> 
                    {s.name}
                 </span>
                 <span className="font-bold text-white">{Math.round((s.value / (stats.totalCarbon || 1)) * 100)}%</span>
               </div>
             ))}
          </div>
        </div>
      </div>
    </div>
  );
};

export default Dashboard;

import React, { useState, useEffect } from 'react';
import { Supplier, Material } from '../types';

interface MasterDataProps {
  suppliers: Supplier[];
  materials: Material[];
  onSupplierAction: (s: Supplier, mode: 'add' | 'edit' | 'delete') => void;
  onMaterialAction: (m: Material, mode: 'add' | 'edit' | 'delete') => void;
}

const MasterData: React.FC<MasterDataProps> = ({ suppliers, materials, onSupplierAction, onMaterialAction }) => {
  const [activeSubTab, setActiveSubTab] = useState<'suppliers' | 'materials'>('suppliers');
  const [isExporting, setIsExporting] = useState(false);
  const [showModal, setShowModal] = useState(false);
  const [editingItem, setEditingItem] = useState<any>(null);
  const [formFields, setFormFields] = useState<any>({});
  const [errors, setErrors] = useState<Record<string, string>>({});

  useEffect(() => {
    if (showModal) {
      if (editingItem) {
        setFormFields({
          name: editingItem.name || '',
          category: editingItem.category || '',
          score: editingItem.sustainabilityScore ?? '',
          certs: editingItem.certifications?.join(', ') || '',
          unit: editingItem.unit || 'kg',
          carbon: editingItem.carbonFactor ?? '',
          recyclability: editingItem.recyclabilityRate ?? '',
          price: editingItem.averagePrice ?? ''
        });
      } else {
        setFormFields({
          name: '', category: '', score: '', certs: '', unit: 'kg', carbon: '', recyclability: '', price: ''
        });
      }
      setErrors({});
    }
  }, [showModal, editingItem, activeSubTab]);

  const handleInputChange = (e: React.ChangeEvent<HTMLInputElement | HTMLSelectElement>) => {
    const { name, value } = e.target;
    setFormFields(prev => ({ ...prev, [name]: value }));
  };

  const handleSave = (e: React.FormEvent) => {
    e.preventDefault();
    const mode = editingItem ? 'edit' : 'add';
    if (activeSubTab === 'suppliers') {
      onSupplierAction({
        id: editingItem?.id || `s-${Date.now()}`,
        name: formFields.name,
        category: formFields.category,
        sustainabilityScore: Number(formFields.score),
        carbonEfficiency: editingItem?.carbonEfficiency || 0,
        certifications: formFields.certs.split(',').map((c: string) => c.trim()).filter((c: string) => c)
      }, mode);
    } else {
      onMaterialAction({
        id: editingItem?.id || `m-${Date.now()}`,
        name: formFields.name,
        category: formFields.category,
        unit: formFields.unit,
        carbonFactor: Number(formFields.carbon),
        recyclabilityRate: Number(formFields.recyclability),
        averagePrice: Number(formFields.price)
      }, mode);
    }
    setShowModal(false);
  };

  return (
    <div className="space-y-6 animate-in fade-in duration-500">
      <header className="flex justify-between items-center">
        <div>
          <h2 className="text-3xl font-bold text-white tracking-tight">Master Data</h2>
          <p className="text-slate-400 mt-1">Foundational registries for materials and suppliers.</p>
        </div>
        <div className="flex gap-3">
          <button onClick={() => setShowModal(true)} className="bg-emerald-600 text-white px-5 py-2.5 rounded-xl font-bold hover:bg-emerald-500 transition-all shadow-lg">
            <i className="fa-solid fa-plus mr-2"></i> Create New
          </button>
        </div>
      </header>

      <div className="bg-slate-900 rounded-2xl border border-slate-800 shadow-xl overflow-hidden">
        <div className="flex border-b border-slate-800 bg-slate-900/50">
          <button onClick={() => setActiveSubTab('suppliers')} className={`px-8 py-4 text-sm font-bold transition-all relative ${activeSubTab === 'suppliers' ? 'text-emerald-400' : 'text-slate-500'}`}>
            Suppliers List {activeSubTab === 'suppliers' && <div className="absolute bottom-0 left-0 w-full h-0.5 bg-emerald-400"></div>}
          </button>
          <button onClick={() => setActiveSubTab('materials')} className={`px-8 py-4 text-sm font-bold transition-all relative ${activeSubTab === 'materials' ? 'text-emerald-400' : 'text-slate-500'}`}>
            Materials Catalog {activeSubTab === 'materials' && <div className="absolute bottom-0 left-0 w-full h-0.5 bg-emerald-400"></div>}
          </button>
        </div>

        <div className="overflow-x-auto">
          {activeSubTab === 'suppliers' ? (
            <table className="w-full text-left">
              <thead className="bg-slate-800/50 text-slate-400 text-xs uppercase font-bold tracking-wider">
                <tr><th className="px-6 py-4">Name</th><th className="px-6 py-4">Category</th><th className="px-6 py-4 text-center">Score</th><th className="px-6 py-4 text-right">Actions</th></tr>
              </thead>
              <tbody className="divide-y divide-slate-800 text-sm">
                {suppliers.map(s => (
                  <tr key={s.id} className="hover:bg-slate-800/30 transition-colors">
                    <td className="px-6 py-4 font-bold text-white">{s.name}</td>
                    <td className="px-6 py-4 text-slate-400">{s.category}</td>
                    <td className="px-6 py-4 text-center">
                      <span className={`px-2 py-1 rounded font-bold text-xs ${s.sustainabilityScore > 80 ? 'bg-emerald-900/40 text-emerald-400 border border-emerald-500/20' : 'bg-amber-900/40 text-amber-400 border border-amber-500/20'}`}>
                        {s.sustainabilityScore}
                      </span>
                    </td>
                    <td className="px-6 py-4 text-right">
                      <button onClick={() => { setEditingItem(s); setShowModal(true); }} className="text-slate-500 hover:text-emerald-400 mr-3"><i className="fa-solid fa-pen"></i></button>
                      <button onClick={() => onSupplierAction(s, 'delete')} className="text-slate-500 hover:text-rose-400"><i className="fa-solid fa-trash"></i></button>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          ) : (
            <table className="w-full text-left">
              <thead className="bg-slate-800/50 text-slate-400 text-xs uppercase font-bold tracking-wider">
                <tr><th className="px-6 py-4">Name</th><th className="px-6 py-4">CO2 Factor</th><th className="px-6 py-4 text-center">Recyclable</th><th className="px-6 py-4 text-right">Actions</th></tr>
              </thead>
              <tbody className="divide-y divide-slate-800 text-sm">
                {materials.map(m => (
                  <tr key={m.id} className="hover:bg-slate-800/30 transition-colors">
                    <td className="px-6 py-4"><div className="font-bold text-white">{m.name}</div><div className="text-xs text-slate-500">{m.category}</div></td>
                    <td className="px-6 py-4 text-slate-300 font-mono">{m.carbonFactor}</td>
