      {showModal && (
        <div className="fixed inset-0 bg-slate-950/80 backdrop-blur-sm z-50 flex items-center justify-center p-4">
          <div className="bg-slate-900 w-full max-w-lg rounded-3xl p-8 shadow-2xl border border-slate-800 animate-in zoom-in duration-200">
            <h3 className="text-2xl font-bold mb-6 text-white">{editingItem ? 'Edit' : 'Create'} {activeSubTab === 'suppliers' ? 'Supplier' : 'Material'}</h3>
            <form onSubmit={handleSave} className="space-y-4">
              <div className="grid grid-cols-2 gap-4">
                <div className="col-span-2 space-y-1">
                  <label className="text-xs font-bold text-slate-400 uppercase">Name *</label>
