          <div className="bg-emerald-900/40 text-emerald-400 px-4 py-2 rounded-lg border border-emerald-500/20 flex items-center gap-2 animate-bounce">
            <i className="fa-solid fa-check-circle"></i>
            <span className="text-sm font-bold">Data Recorded</span>
