                  </div>
                  <div className="space-y-1">
                    <label className="text-xs font-bold text-slate-400 uppercase tracking-wide">Consumption</label>
                    <input type="number" className="w-full bg-slate-800 border border-slate-700 p-3 rounded-xl text-white outline-none focus:ring-2 focus:ring-amber-500" value={eFormData.amount || ''} onChange={e => setEFormData({...eFormData, amount: Number(e.target.value)})} />
