                  <select className="w-full bg-slate-800 border border-slate-700 p-3 rounded-xl text-white outline-none focus:ring-2 focus:ring-amber-500" value={eFormData.source} onChange={e => setEFormData({...eFormData, source: e.target.value as any})}>
