                    <td className="py-3 font-bold text-slate-300">{materials.find(m => m.id === p.materialId)?.name}</td>
                    <td className="py-3 text-right text-emerald-400 font-bold">${p.totalCost}</td>
                  </tr>
                )) : energy.slice(0, 8).map(e => (
                  <tr key={e.id} className="hover:bg-slate-800/40">
                    <td className="py-3 text-slate-500">{e.date}</td>
                    <td className="py-3 font-bold text-slate-300">{e.source}</td>
                    <td className="py-3 text-right text-amber-400 font-bold">{e.amount} {e.unit}</td>
