                    <td className="py-4 text-slate-400 font-bold text-xs">{p.date}</td>
                    <td className="py-4 px-4 font-bold text-slate-700 dark:text-slate-300">{materials.find(m => m.id === p.materialId)?.name}</td>
                    <td className="py-4 text-right text-emerald-600 dark:text-emerald-400 font-black tracking-tight">${p.totalCost}</td>
                  </tr>
                )) : energy.slice(0, 10).map(e => (
                  <tr key={e.id} className="hover:bg-slate-50/50 dark:hover:bg-slate-800/40 transition-colors">
                    <td className="py-4 text-slate-400 font-bold text-xs">{e.date}</td>
                    <td className="py-4 px-4 font-bold text-slate-700 dark:text-slate-300">{e.source}</td>
                    <td className="py-4 text-right text-amber-600 dark:text-amber-400 font-black tracking-tight">{e.amount} {e.unit}</td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </div>
      </div>
    </div>
  );
};

export default DataManagement;

import React, { useMemo, useState } from 'react';
import { Supplier, Material, ProcurementRecord, Recommendation } from '../types';

interface RecommendationEngineProps {
  suppliers: Supplier[];
  materials: Material[];
  procurement: ProcurementRecord[];
}

const RecommendationEngine: React.FC<RecommendationEngineProps> = ({ suppliers, materials, procurement }) => {
  const [applying, setApplying] = useState<string | null>(null);

  const recommendations = useMemo(() => {
    const recs: Recommendation[] = [];
    const highImpactMaterials = materials.filter(m => m.carbonFactor > 10);
    highImpactMaterials.forEach(m => {
      const alternative = materials.find(alt => alt.category === m.category && alt.carbonFactor < m.carbonFactor);
      if (alternative) {
        recs.push({
          id: `rec-m-${m.id}`,
          type: 'MATERIAL',
          title: `Switch Material: ${m.name}`,
          description: `Optimize by replacing high-carbon '${m.name}' with '${alternative.name}'. Potentially reduces footprint by ${Math.round((1 - alternative.carbonFactor/m.carbonFactor) * 100)}%.`,
          impact: 'High'
        });
      }
    });

    const activeSupplierIds = new Set(procurement.map(p => p.supplierId));
    suppliers.filter(s => activeSupplierIds.has(s.id) && s.sustainabilityScore < 60).forEach(s => {
      const betterSupplier = suppliers.find(alt => alt.category === s.category && alt.sustainabilityScore > 80);
      if (betterSupplier) {
        recs.push({
          id: `rec-s-${s.id}`,
          type: 'SUPPLIER',
          title: `Supply Chain Shift: ${s.name}`,
          description: `Transition to vendor '${betterSupplier.name}' (ESG Score: ${betterSupplier.sustainabilityScore}) to significantly improve system sustainability rating.`,
          impact: 'Medium'
        });
      }
    });

    return recs;
  }, [suppliers, materials, procurement]);

  const handleApply = (id: string) => {
    setApplying(id);
    setTimeout(() => { setApplying(null); alert("Strategy transformation initiated!"); }, 1200);
  };

  return (
    <div className="space-y-8 animate-in slide-in-from-bottom duration-500">
      <header>
        <h2 className="text-3xl font-black text-slate-900 dark:text-white tracking-tight">Recommendation Engine</h2>
        <p className="text-slate-500 dark:text-slate-400 mt-1 font-medium">Algorithmic suggestions for circular economy transition.</p>
      </header>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
        {recommendations.length > 0 ? recommendations.map(rec => (
          <div key={rec.id} className="bg-white dark:bg-slate-900 rounded-[32px] border border-slate-200 dark:border-slate-800 p-8 shadow-sm dark:shadow-2xl flex flex-col group relative overflow-hidden hover:border-emerald-500/30 transition-all">
            <div className={`absolute -right-8 -top-8 opacity-[0.05] dark:opacity-[0.03] group-hover:opacity-10 dark:group-hover:opacity-10 transition-opacity`}>
              <i className={`fa-solid ${rec.type === 'MATERIAL' ? 'fa-box-open' : 'fa-truck-arrow-right'} text-[140px] text-slate-900 dark:text-white`}></i>
            </div>
            <div className="mb-6">
              <span className={`px-3 py-1 rounded-full text-[10px] font-black uppercase tracking-widest ${rec.impact === 'High' ? 'bg-rose-50 text-rose-600 dark:bg-rose-900/40 dark:text-rose-400 border border-rose-500/10' : 'bg-blue-50 text-blue-600 dark:bg-blue-900/40 dark:text-blue-400 border border-blue-500/10'}`}>
                {rec.impact} Environmental Impact
              </span>
            </div>
            <h3 className="text-xl font-black text-slate-900 dark:text-white mb-3 tracking-tight">{rec.title}</h3>
            <p className="text-slate-500 dark:text-slate-400 text-sm leading-relaxed mb-10 font-medium">{rec.description}</p>
            <button 
              onClick={() => handleApply(rec.id)}
              disabled={!!applying}
              className="mt-auto w-full bg-slate-900 dark:bg-slate-800 text-white dark:text-emerald-400 py-4 rounded-2xl font-black uppercase tracking-widest text-[10px] hover:bg-emerald-600 dark:hover:bg-emerald-600 hover:text-white transition-all flex items-center justify-center gap-3 border border-transparent dark:border-slate-700 shadow-lg shadow-black/10 active:scale-[0.98]"
            >
              {applying === rec.id ? <i className="fa-solid fa-sync animate-spin"></i> : <i className="fa-solid fa-bolt-lightning text-emerald-500"></i>}
              {applying === rec.id ? 'Processing' : 'Execute Optimization'}
            </button>
          </div>
        )) : (
          <div className="col-span-full py-20 text-center bg-white dark:bg-slate-900 rounded-[32px] border border-dashed border-slate-200 dark:border-slate-800">
             <i className="fa-solid fa-check-double text-4xl text-emerald-500 mb-4 opacity-30"></i>
             <h3 className="text-xl font-bold text-slate-900 dark:text-white">System Optimized</h3>
             <p className="text-slate-400 font-medium">All current procurement matches best-available sustainability standards.</p>
          </div>
        )}
      </div>
    </div>
  );
};

export default RecommendationEngine;

import React, { useMemo, useState } from 'react';
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, AreaChart, Area, Cell, PieChart, Pie } from 'recharts';
import { Supplier, Material, ProcurementRecord, EnergyRecord, User } from '../types';
import KPICard from '../components/KPICard';

interface DashboardProps {
  suppliers: Supplier[];
  materials: Material[];
  procurement: ProcurementRecord[];
  energy: EnergyRecord[];
  currentUser: User;
  theme: 'light' | 'dark';
}

const Dashboard: React.FC<DashboardProps> = ({ suppliers, materials, procurement, energy, currentUser, theme }) => {
  const [isExporting, setIsExporting] = useState(false);

  const stats = useMemo(() => {
    const energyCarbon = energy.reduce((sum, e) => sum + e.carbonEquivalent, 0);
    const materialCarbon = procurement.reduce((sum, p) => {
      const mat = materials.find(m => m.id === p.materialId);
      return sum + (p.quantity * (mat?.carbonFactor || 0));
    }, 0);
    const totalCarbon = energyCarbon + materialCarbon;
    const avgSupplierScore = suppliers.length > 0 ? Math.round(suppliers.reduce((sum, s) => sum + s.sustainabilityScore, 0) / suppliers.length) : 0;
    const totalSpend = procurement.reduce((sum, p) => sum + p.totalCost, 0);
    const totalQty = procurement.reduce((sum, p) => sum + p.quantity, 0);
    const avgRecyclability = totalQty > 0 ? Math.round(procurement.reduce((sum, p) => sum + (p.quantity * (materials.find(m => m.id === p.materialId)?.recyclabilityRate || 0)), 0) / totalQty) : 0;

    return { totalCarbon, avgSupplierScore, totalSpend, avgRecyclability, energyCarbon, materialCarbon };
  }, [suppliers, materials, procurement, energy]);

  const handleExport = () => {
    setIsExporting(true);

    // Prepare CSV Content
    const csvRows = [
      ["Metric", "Value", "Unit"],
      ["Total Carbon Footprint", stats.totalCarbon.toFixed(2), "kg CO2"],
      ["Energy Carbon Impact", stats.energyCarbon.toFixed(2), "kg CO2"],
      ["Procurement Carbon Impact", stats.materialCarbon.toFixed(2), "kg CO2"],
      ["Average Supplier ESG Score", stats.avgSupplierScore, "points / 100"],
      ["Total Material Spend", stats.totalSpend.toFixed(2), "USD"],
      ["Average Recyclability Rate", stats.avgRecyclability, "%"],
      ["User Session", currentUser.username, "Login"],
      ["Export Timestamp", new Date().toLocaleString(), "Date"]
    ];

    const csvContent = csvRows.map(row => row.join(",")).join("\n");
    const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' });
    const url = URL.createObjectURL(blob);

    const link = document.createElement("a");
    link.setAttribute("href", url);
    link.setAttribute("download", `GreenERP_KPI_Export_${new Date().toISOString().split('T')[0]}.csv`);
    document.body.appendChild(link);

    setTimeout(() => {
      link.click();
      document.body.removeChild(link);
      setIsExporting(false);
    }, 1000);
  };

  const trendData = [
    { month: 'Jul', co2: 2400 },
    { month: 'Aug', co2: 2100 },
    { month: 'Sep', co2: 2800 },
    { month: 'Oct', co2: Math.round(stats.totalCarbon) || 2500 },
  ];

  const emissionBySourceData = [
    { name: 'Energy', value: stats.energyCarbon, color: '#10b981' },
    { name: 'Procurement', value: stats.materialCarbon, color: '#3b82f6' },
  ];

  const chartColors = theme === 'dark' ? {
    grid: '#1e293b',
    text: '#94a3b8',
    tooltipBg: '#0f172a',
    tooltipBorder: '#1e293b'
  } : {
    grid: '#e2e8f0',
    text: '#64748b',
    tooltipBg: '#ffffff',
    tooltipBorder: '#e2e8f0'
  };

  return (
    <div className="space-y-8 animate-in fade-in duration-500">
      <header className="flex justify-between items-center">
        <div>
          <div className="flex items-center gap-3 mb-1">
            <h2 className="text-3xl font-extrabold text-slate-900 dark:text-white tracking-tight">System Dashboard</h2>
            <div className="px-3 py-1 bg-emerald-50 dark:bg-emerald-900/40 text-emerald-600 dark:text-emerald-400 text-[10px] font-extrabold uppercase rounded-full border border-emerald-500/20 shadow-sm flex items-center gap-2">
              <i className="fa-solid fa-user-circle"></i>
              Session: {currentUser.username}
            </div>
          </div>
          <p className="text-slate-500 dark:text-slate-400 font-medium">Real-time environmental performance monitoring.</p>
        </div>
        <button onClick={handleExport} disabled={isExporting} className="bg-emerald-600 text-white px-5 py-2.5 rounded-xl font-bold shadow-lg shadow-emerald-500/20 hover:bg-emerald-500 transition-all disabled:opacity-50 flex items-center gap-2">
          {isExporting ? <i className="fa-solid fa-spinner animate-spin"></i> : <i className="fa-solid fa-download"></i>}
          {isExporting ? 'Exporting...' : 'Export CSV'}
        </button>
      </header>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
        <KPICard title="Total Carbon" value={stats.totalCarbon.toLocaleString()} unit="kg CO2" icon="fa-cloud" color="rose" />
        <KPICard title="Avg Supplier Score" value={stats.avgSupplierScore} unit="/ 100" icon="fa-award" color="emerald" />
        <KPICard title="Total Material Spend" value={`$${(stats.totalSpend / 1000).toFixed(1)}k`} icon="fa-wallet" color="indigo" />
        <KPICard title="Avg Recyclability" value={stats.avgRecyclability} unit="%" icon="fa-recycle" color="amber" />
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
        <div className="lg:col-span-2 bg-white dark:bg-slate-900 p-8 rounded-3xl border border-slate-200 dark:border-slate-800 shadow-sm dark:shadow-xl">
          <h3 className="text-lg font-bold mb-8 text-slate-900 dark:text-white">Emission Trend (Q3-Q4)</h3>
          <div className="h-[300px]">
            <ResponsiveContainer width="100%" height="100%">
              <AreaChart data={trendData}>
                <CartesianGrid strokeDasharray="3 3" vertical={false} stroke={chartColors.grid} />
                <XAxis dataKey="month" axisLine={false} tickLine={false} tick={{fill: chartColors.text, fontSize: 11, fontWeight: 600}} />
                <YAxis axisLine={false} tickLine={false} tick={{fill: chartColors.text, fontSize: 11, fontWeight: 600}} />
                <Tooltip 
                  contentStyle={{ backgroundColor: chartColors.tooltipBg, borderRadius: '16px', border: `1px solid ${chartColors.tooltipBorder}`, boxShadow: '0 20px 25px -5px rgb(0 0 0 / 0.1)', color: theme === 'dark' ? '#fff' : '#000' }} 
                  itemStyle={{ color: '#10b981', fontWeight: 700 }}
                />
                <Area type="monotone" dataKey="co2" stroke="#10b981" strokeWidth={4} fill="url(#colorEmerald)" fillOpacity={1} />
                <defs>
                  <linearGradient id="colorEmerald" x1="0" y1="0" x2="0" y2="1">
                    <stop offset="5%" stopColor="#10b981" stopOpacity={0.15}/>
                    <stop offset="95%" stopColor="#10b981" stopOpacity={0}/>
                  </linearGradient>
                </defs>
              </AreaChart>
            </ResponsiveContainer>
          </div>
        </div>
        <div className="bg-white dark:bg-slate-900 p-8 rounded-3xl border border-slate-200 dark:border-slate-800 shadow-sm dark:shadow-xl flex flex-col items-center">
          <h3 className="text-lg font-bold mb-6 text-slate-900 dark:text-white text-center">Impact Source Breakdown</h3>
          <div className="h-[250px] w-full relative">
            <ResponsiveContainer width="100%" height="100%">
              <PieChart>
                <Pie data={emissionBySourceData} cx="50%" cy="50%" innerRadius={70} outerRadius={95} paddingAngle={10} dataKey="value">
                  {emissionBySourceData.map((entry, index) => <Cell key={`cell-${index}`} fill={entry.color} stroke="none" />)}
                </Pie>
                <Tooltip 
                  contentStyle={{ backgroundColor: chartColors.tooltipBg, borderRadius: '16px', border: `1px solid ${chartColors.tooltipBorder}` }}
                  itemStyle={{ color: theme === 'dark' ? '#fff' : '#000', fontWeight: 700 }}
                />
              </PieChart>
            </ResponsiveContainer>
            <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 text-center pointer-events-none">
                <p className="text-[10px] text-slate-400 dark:text-slate-500 font-extrabold uppercase tracking-widest">Total CO2</p>
                <p className="text-2xl font-black text-slate-900 dark:text-white leading-none">{Math.round(stats.totalCarbon / 1000)}t</p>
            </div>
          </div>
          <div className="w-full space-y-4 mt-6">
             {emissionBySourceData.map(s => (
               <div key={s.name} className="flex justify-between items-center text-xs p-3 bg-slate-50 dark:bg-slate-800/50 rounded-xl border border-slate-100 dark:border-slate-800">
                 <span className="flex items-center gap-2 text-slate-600 dark:text-slate-300 font-bold">
                    <div className="w-3 h-3 rounded-full shadow-sm" style={{backgroundColor: s.color}}></div> 
                    {s.name}
                 </span>
                 <span className="font-black text-slate-900 dark:text-white">{Math.round((s.value / (stats.totalCarbon || 1)) * 100)}%</span>
               </div>
             ))}
          </div>
        </div>
      </div>
    </div>
  );
};

export default Dashboard;

import React, { useState, useEffect } from 'react';
import { UserRole, User, Supplier, Material, ProcurementRecord, EnergyRecord } from './types';
import Sidebar from './components/Sidebar';
import Dashboard from './views/Dashboard';
import MasterData from './views/MasterData';
import DataManagement from './views/DataManagement';
import RecommendationEngine from './views/RecommendationEngine';
import { api } from './api';

const App: React.FC = () => {
  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [activeTab, setActiveTab] = useState('dashboard');
  const [isSyncing, setIsSyncing] = useState(false);
  const [isGeneratingReport, setIsGeneratingReport] = useState(false);
  const [showUserModal, setShowUserModal] = useState(false);
  const [loginError, setLoginError] = useState<string | null>(null);
  const [theme, setTheme] = useState<'light' | 'dark'>(() => {
    return (localStorage.getItem('erp-theme') as 'light' | 'dark') || 'dark';
  });

  const [suppliers, setSuppliers] = useState<Supplier[]>([]);
  const [materials, setMaterials] = useState<Material[]>([]);
  const [procurement, setProcurement] = useState<ProcurementRecord[]>([]);
  const [energy, setEnergy] = useState<EnergyRecord[]>([]);
  const [users, setUsers] = useState<User[]>([]);

  useEffect(() => {
    document.documentElement.classList.toggle('dark', theme === 'dark');
    localStorage.setItem('erp-theme', theme);
  }, [theme]);

  useEffect(() => {
    loadAllData();
  }, []);

  const loadAllData = async () => {
    setIsSyncing(true);
    try {
      const [u, s, m, p, e] = await Promise.all([
        api.getUsers(),
        api.getSuppliers(),
        api.getMaterials(),
        api.getProcurement(),
        api.getEnergy()
      ]);
      setUsers(u);
      setSuppliers(s);
      setMaterials(m);
      setProcurement(p);
      setEnergy(e);
    } catch (err) {
      console.error("Failed to sync with database", err);
    } finally {
      setIsSyncing(false);
    }
  };

  const handleLogin = async (e: React.FormEvent) => {
    e.preventDefault();
    setLoginError(null);
    setIsSyncing(true);

    const formData = new FormData(e.currentTarget as HTMLFormElement);
    const username = (formData.get('username') as string).trim();
    const role = formData.get('role') as UserRole;

    if (!username) {
      setLoginError("Username is required.");
      setIsSyncing(false);
      return;
    }

    const userExists = await api.checkUserExists(username);
    if (!userExists) {
      setLoginError(`User "${username}" not found.`);
      setIsSyncing(false);
      return;
    }

    const user = await api.login(username, role);
    if (user) {
      setCurrentUser(user);
      loadAllData();
    } else {
      setLoginError(`Invalid role for "${username}".`);
    }
    setIsSyncing(false);
  };

  const handleLogout = () => {
    setCurrentUser(null);
    setLoginError(null);
    setActiveTab('dashboard');
  };

  const toggleTheme = () => setTheme(prev => prev === 'light' ? 'dark' : 'light');

  const handleDownloadReport = () => {
    setIsGeneratingReport(true);

    const energyCarbon = energy.reduce((sum, e) => sum + e.carbonEquivalent, 0);
    const materialCarbon = procurement.reduce((sum, p) => {
      const mat = materials.find(m => m.id === p.materialId);
      return sum + (p.quantity * (mat?.carbonFactor || 0));
    }, 0);
    const totalCarbon = energyCarbon + materialCarbon;
    const avgScore = suppliers.length > 0 ? (suppliers.reduce((sum, s) => sum + s.sustainabilityScore, 0) / suppliers.length).toFixed(1) : 0;

    const reportContent = `
=========================================
GREEN ERP - SUSTAINABILITY EXECUTIVE REPORT
=========================================
Generated on: ${new Date().toLocaleString()}
System User: ${currentUser?.username} (Role: ${currentUser?.role})

1. ENVIRONMENTAL KPI SUMMARY
---------------------------
Total Carbon Footprint: ${totalCarbon.toFixed(2)} kg CO2
   - Energy Scope: ${energyCarbon.toFixed(2)} kg CO2
   - Procurement Scope: ${materialCarbon.toFixed(2)} kg CO2
Avg. Recyclability Rate: ${(procurement.length > 0 ? 75 : 0)}%

2. SUPPLY CHAIN ESG PERFORMANCE
---------------------------
Average Supplier Score: ${avgScore} / 100
Total Suppliers Registered: ${suppliers.length}
Top Rated Supplier: ${suppliers.sort((a,b) => b.sustainabilityScore - a.sustainabilityScore)[0]?.name || 'N/A'}

3. PROCUREMENT INSIGHTS
---------------------------
Total Materials Procured: ${procurement.length} transactions
Total Financial Spend: $${procurement.reduce((sum, p) => sum + p.totalCost, 0).toFixed(2)}

4. SYSTEM RECOMMENDATIONS
---------------------------
- Transition to higher-rated ESG suppliers where score is < 60%.
- Review energy consumption during peak procurement cycles.
- Prioritize materials with Carbon Factor < 1.0.

End of Report.
=========================================
    `;

    const blob = new Blob([reportContent], { type: 'text/plain' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement("a");
    link.setAttribute("href", url);
    link.setAttribute("download", `Sustainability_Report_${new Date().toISOString().split('T')[0]}.txt`);

    setTimeout(() => {
      link.click();
      URL.revokeObjectURL(url);
      setIsGeneratingReport(false);
    }, 1500);
  };

  const addProcurement = async (p: Omit<ProcurementRecord, 'id'>) => {
    const newRecord = { ...p, id: `p-${Date.now()}` };
    await api.addProcurement(newRecord);
    setProcurement(prev => [newRecord, ...prev]);
  };

  const addEnergy = async (e: Omit<EnergyRecord, 'id'>) => {
    const newRecord = { ...e, id: `e-${Date.now()}` };
    await api.addEnergy(newRecord);
    setEnergy(prev => [newRecord, ...prev]);
  };

  const manageSupplier = async (supplier: Supplier, mode: 'add' | 'edit' | 'delete') => {
    if (mode === 'delete') {
      await api.deleteSupplier(supplier.id);
      setSuppliers(prev => prev.filter(s => s.id !== supplier.id));
    } else {
      await api.saveSupplier(supplier, mode);
      if (mode === 'add') setSuppliers(prev => [...prev, supplier]);
      else setSuppliers(prev => prev.map(s => s.id === supplier.id ? supplier : s));
    }
  };

  const manageMaterial = async (material: Material, mode: 'add' | 'edit' | 'delete') => {
    if (mode === 'delete') {
      await api.deleteMaterial(material.id);
      setMaterials(prev => prev.filter(m => m.id !== material.id));
    } else {
      await api.saveMaterial(material, mode);
      if (mode === 'add') setMaterials(prev => [...prev, material]);
      else setMaterials(prev => prev.map(m => m.id === material.id ? material : m));
    }
  };

  const handleCreateUser = async (e: React.FormEvent) => {
    e.preventDefault();
    const formData = new FormData(e.currentTarget as HTMLFormElement);
    const username = (formData.get('username') as string).trim();
    const role = formData.get('role') as UserRole;

    if (!username) return alert("User name is required.");
    if (await api.checkUserExists(username)) return alert("Username taken.");

    const newUser: User = { id: `u-${Date.now()}`, username, role };
    await api.createUser(newUser);
    setUsers(prev => [...prev, newUser]);
    setShowUserModal(false);
  };

  const deleteUser = async (user: User) => {
    if (user.id === currentUser?.id) return alert("Cannot delete yourself.");
    if (confirm(`Remove "${user.username}"?`)) {
      await api.deleteUser(user.id);
      setUsers(prev => prev.filter(u => u.id !== user.id));
    }
  };

  const renderContent = () => {
    if (!currentUser) return null;
    switch(activeTab) {
      case 'dashboard':
        return <Dashboard suppliers={suppliers} materials={materials} procurement={procurement} energy={energy} currentUser={currentUser} theme={theme} />;
      case 'master-data':
        return <MasterData suppliers={suppliers} materials={materials} onSupplierAction={manageSupplier} onMaterialAction={manageMaterial} />;
      case 'data-management':
        return <DataManagement materials={materials} suppliers={suppliers} procurement={procurement} energy={energy} currentRole={currentUser.role} onAddProcurement={addProcurement} onAddEnergy={addEnergy} />;
      case 'recommendations':
        return <RecommendationEngine suppliers={suppliers} materials={materials} procurement={procurement} />;
      case 'reports':
        return (
          <div className="flex flex-col items-center justify-center py-24 text-center">
             <div className="w-20 h-20 bg-emerald-500/10 dark:bg-emerald-900/50 text-emerald-600 dark:text-emerald-400 rounded-full flex items-center justify-center mb-6 border border-emerald-500/20 shadow-inner">
                <i className={`fa-solid ${isGeneratingReport ? 'fa-spinner animate-spin' : 'fa-file-pdf'} text-3xl`}></i>
             </div>
             <h3 className="text-2xl font-bold text-slate-900 dark:text-white">Generate Sustainability Report</h3>
             <p className="text-slate-500 dark:text-slate-400 mt-2 max-w-sm">Compile all environmental KPIs and procurement analytics into a downloadable document.</p>
             <button onClick={handleDownloadReport} disabled={isGeneratingReport} className="mt-8 bg-emerald-600 text-white px-8 py-3 rounded-xl font-bold shadow-lg hover:bg-emerald-500 transition-all disabled:opacity-50 flex items-center gap-2">
               {isGeneratingReport ? <i className="fa-solid fa-spinner animate-spin"></i> : <i className="fa-solid fa-download"></i>}
               {isGeneratingReport ? 'Processing...' : 'Download Report'}
             </button>
          </div>
        );
      case 'users':
        return (
          <div className="bg-white dark:bg-slate-900 p-8 rounded-2xl border border-slate-200 dark:border-slate-800 shadow-xl max-w-4xl mx-auto">
             <div className="flex justify-between items-center mb-8">
                <div>
                  <h3 className="text-2xl font-bold text-slate-900 dark:text-white">Manage Personnel</h3>
                  <p className="text-slate-500 dark:text-slate-400 text-sm">Create and manage access for system users.</p>
                </div>
                <button onClick={() => setShowUserModal(true)} className="bg-emerald-600 text-white px-5 py-2.5 rounded-xl font-bold hover:bg-emerald-500 transition-all shadow-lg">Add User</button>
             </div>
             <div className="divide-y divide-slate-100 dark:divide-slate-800 border-t border-slate-100 dark:border-slate-800">
               {users.map(u => (
                 <div key={u.id} className="py-4 flex justify-between items-center px-2">
                    <div className="flex items-center gap-3">
                      <div className="w-10 h-10 rounded-full bg-slate-100 dark:bg-slate-800 border border-slate-200 dark:border-slate-700 flex items-center justify-center font-bold text-emerald-600 dark:text-emerald-400">{u.username.charAt(0).toUpperCase()}</div>
                      <div>
                        <p className="font-bold text-slate-900 dark:text-white">{u.username}</p>
                        <p className="text-xs text-slate-500 font-bold uppercase">{u.role.replace('_', ' ')}</p>
                      </div>
                    </div>
                    <button onClick={() => deleteUser(u)} className="text-slate-400 hover:text-rose-500 p-2 transition-colors"><i className="fa-solid fa-trash"></i></button>
                 </div>
               ))}
             </div>
             {showUserModal && (
               <div className="fixed inset-0 bg-slate-950/60 backdrop-blur-sm z-[100] flex items-center justify-center p-4">
                 <div className="bg-white dark:bg-slate-900 w-full max-w-md rounded-3xl p-8 shadow-2xl border border-slate-200 dark:border-slate-800 animate-in zoom-in duration-200">
                    <h3 className="text-2xl font-bold mb-6 text-slate-900 dark:text-white">Create System User</h3>
                    <form onSubmit={handleCreateUser} className="space-y-4">
                      <div className="space-y-1">
                        <label className="text-xs font-bold text-slate-500 dark:text-slate-400 uppercase">User Name</label>
                        <input name="username" required className="w-full bg-slate-50 dark:bg-slate-800 border border-slate-200 dark:border-slate-700 p-3 rounded-xl outline-none text-slate-900 dark:text-white focus:ring-2 focus:ring-emerald-500 placeholder-slate-400" placeholder="e.g. Rahul" />
                      </div>
                      <div className="space-y-1">
                        <label className="text-xs font-bold text-slate-500 dark:text-slate-400 uppercase">System Role</label>
                        <select name="role" required className="w-full bg-slate-50 dark:bg-slate-800 border border-slate-200 dark:border-slate-700 p-3 rounded-xl outline-none text-slate-900 dark:text-white focus:ring-2 focus:ring-emerald-500">
                          <option value={UserRole.PROCUREMENT_MANAGER}>Procurement Manager</option>
                          <option value={UserRole.SUSTAINABILITY_MANAGER}>Sustainability Manager</option>
                          <option value={UserRole.ADMIN}>Administrator</option>
                        </select>
                      </div>
                      <div className="flex gap-3 mt-8">
                        <button type="button" onClick={() => setShowUserModal(false)} className="flex-1 py-3 rounded-xl border border-slate-200 dark:border-slate-700 text-slate-500 dark:text-slate-300 font-bold hover:bg-slate-100 dark:hover:bg-slate-800">Cancel</button>
                        <button type="submit" className="flex-1 bg-emerald-600 text-white py-3 rounded-xl font-bold hover:bg-emerald-500 shadow-lg">Create User</button>
                      </div>
                    </form>
                 </div>
               </div>
             )}
          </div>
        );
      default: return null;
    }
  };

  if (!currentUser) {
    return (
      <div className="min-h-screen bg-slate-50 dark:bg-slate-950 flex items-center justify-center p-4 transition-colors duration-500">
        <div className="bg-white dark:bg-slate-900 w-full max-w-md rounded-3xl p-8 shadow-2xl border border-slate-200 dark:border-slate-800 animate-in zoom-in duration-300">
          <div className="text-center mb-8">
            <div className="w-16 h-16 bg-emerald-50 dark:bg-emerald-900/50 text-emerald-600 dark:text-emerald-400 border border-emerald-500/20 rounded-2xl flex items-center justify-center text-3xl mx-auto mb-4 shadow-sm">
              <i className="fa-solid fa-leaf"></i>
            </div>
            <h1 className="text-3xl font-extrabold text-slate-900 dark:text-white tracking-tight">Green ERP</h1>
            <p className="text-slate-500 dark:text-slate-400 mt-2 font-medium">Sustainability Decision Support</p>
          </div>

          <form onSubmit={handleLogin} className="space-y-5">
            <div className="space-y-2">
              <label className="text-xs font-bold text-slate-500 dark:text-slate-400 uppercase tracking-widest ml-1">Username</label>
              <input 
                name="username"
                type="text" 
                disabled={isSyncing}
                className={`w-full bg-slate-50 dark:bg-slate-800 border p-4 rounded-xl outline-none transition-all font-medium text-slate-900 dark:text-white placeholder-slate-400 ${loginError ? 'border-rose-500 ring-2 ring-rose-500/10' : 'border-slate-200 dark:border-slate-700 focus:ring-2 focus:ring-emerald-500'}`}
                placeholder="Enter registered name"
              />
              {loginError && <p className="text-rose-500 text-xs font-bold ml-1 animate-pulse"><i className="fa-solid fa-circle-exclamation mr-1"></i> {loginError}</p>}
            </div>

            <div className="space-y-2">
              <label className="text-xs font-bold text-slate-500 dark:text-slate-400 uppercase tracking-widest ml-1">Select Role</label>
              <select name="role" disabled={isSyncing} className="w-full bg-slate-50 dark:bg-slate-800 border border-slate-200 dark:border-slate-700 p-4 rounded-xl outline-none font-medium text-slate-900 dark:text-white focus:ring-2 focus:ring-emerald-500">
                <option value={UserRole.ADMIN}>Administrator</option>
                <option value={UserRole.PROCUREMENT_MANAGER}>Procurement Manager</option>
                <option value={UserRole.SUSTAINABILITY_MANAGER}>Sustainability Manager</option>
              </select>
            </div>

            <button type="submit" disabled={isSyncing} className="w-full bg-slate-900 dark:bg-emerald-600 text-white py-4 rounded-xl font-bold text-lg hover:bg-slate-800 dark:hover:bg-emerald-500 transition-all shadow-xl flex items-center justify-center gap-2 disabled:opacity-50">
              {isSyncing ? <i className="fa-solid fa-spinner animate-spin"></i> : 'Sign In'} <i className="fa-solid fa-arrow-right"></i>
            </button>
          </form>

          <div className="mt-8 flex justify-center">
            <button onClick={toggleTheme} className="text-slate-400 hover:text-emerald-500 text-sm font-bold flex items-center gap-2">
              <i className={`fa-solid ${theme === 'dark' ? 'fa-sun' : 'fa-moon'}`}></i>
              Switch to {theme === 'dark' ? 'Light' : 'Dark'} Mode
            </button>
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-slate-50 dark:bg-slate-950 text-slate-900 dark:text-slate-100 transition-colors duration-300">
      {isSyncing && (
        <div className="fixed top-0 left-0 w-full h-1 z-[200]">
          <div className="h-full bg-emerald-500 animate-pulse"></div>
        </div>
      )}
      <Sidebar 
        currentRole={currentUser.role} 
        activeTab={activeTab} 
        setActiveTab={setActiveTab} 
        onLogout={handleLogout}
        theme={theme}
        onToggleTheme={toggleTheme}
      />
      <main className="pl-64 min-h-screen">
        <div className="p-10 max-w-[1400px] mx-auto">{renderContent()}</div>
      </main>
    </div>
  );
};

export default App;

import React, { useMemo, useState } from 'react';
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, AreaChart, Area, Cell, PieChart, Pie } from 'recharts';
import { Supplier, Material, ProcurementRecord, EnergyRecord, User } from '../types';
import KPICard from '../components/KPICard';

interface DashboardProps {
  suppliers: Supplier[];
  materials: Material[];
  procurement: ProcurementRecord[];
  energy: EnergyRecord[];
  currentUser: User;
  theme: 'light' | 'dark';
}

const Dashboard: React.FC<DashboardProps> = ({ suppliers, materials, procurement, energy, currentUser, theme }) => {
  const [isExporting, setIsExporting] = useState(false);
  const [showLogic, setShowLogic] = useState(false);

  const stats = useMemo(() => {
    const energyCarbon = energy.reduce((sum, e) => sum + e.carbonEquivalent, 0);
    const materialCarbon = procurement.reduce((sum, p) => {
      const mat = materials.find(m => m.id === p.materialId);
      return sum + (p.quantity * (mat?.carbonFactor || 0));
    }, 0);
    const totalCarbon = energyCarbon + materialCarbon;
    const avgSupplierScore = suppliers.length > 0 ? Math.round(suppliers.reduce((sum, s) => sum + s.sustainabilityScore, 0) / suppliers.length) : 0;
    const totalSpend = procurement.reduce((sum, p) => sum + p.totalCost, 0);
    const totalQty = procurement.reduce((sum, p) => sum + p.quantity, 0);
    const avgRecyclability = totalQty > 0 ? Math.round(procurement.reduce((sum, p) => {
      const mat = materials.find(m => m.id === p.materialId);
      return sum + (p.quantity * (mat?.recyclabilityRate || 0));
    }, 0) / totalQty) : 0;

    return { totalCarbon, avgSupplierScore, totalSpend, avgRecyclability, energyCarbon, materialCarbon, totalQty };
  }, [suppliers, materials, procurement, energy]);

  const handleExport = () => {
    setIsExporting(true);
    const csvRows = [
      ["Metric", "Value", "Unit"],
      ["Total Carbon Footprint", stats.totalCarbon.toFixed(2), "kg CO2"],
      ["Energy Carbon Impact", stats.energyCarbon.toFixed(2), "kg CO2"],
      ["Procurement Carbon Impact", stats.materialCarbon.toFixed(2), "kg CO2"],
      ["Average Supplier ESG Score", stats.avgSupplierScore, "points / 100"],
      ["Total Material Spend", stats.totalSpend.toFixed(2), "USD"],
      ["Average Recyclability Rate", stats.avgRecyclability, "%"]
    ];
    const csvContent = csvRows.map(row => row.join(",")).join("\n");
    const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement("a");
    link.setAttribute("href", url);
    link.setAttribute("download", `GreenERP_KPI_${new Date().toISOString().split('T')[0]}.csv`);
    document.body.appendChild(link);
    setTimeout(() => {
      link.click();
      document.body.removeChild(link);
      setIsExporting(false);
    }, 800);
  };

  const trendData = [
    { month: 'Jul', co2: 2400 },
    { month: 'Aug', co2: 2100 },
    { month: 'Sep', co2: 2800 },
    { month: 'Oct', co2: Math.round(stats.totalCarbon) || 2500 },
  ];

  const emissionBySourceData = [
    { name: 'Energy (Scope 2)', value: stats.energyCarbon, color: '#10b981' },
    { name: 'Supply Chain (Scope 3)', value: stats.materialCarbon, color: '#3b82f6' },
  ];

  const chartColors = theme === 'dark' ? {
    grid: '#1e293b', text: '#94a3b8', tooltipBg: '#0f172a', tooltipBorder: '#1e293b'
  } : {
    grid: '#e2e8f0', text: '#64748b', tooltipBg: '#ffffff', tooltipBorder: '#e2e8f0'
  };

  return (
    <div className="space-y-8 animate-in fade-in duration-500 pb-12">
      <header className="flex justify-between items-end">
        <div>
          <div className="flex items-center gap-3 mb-1">
            <h2 className="text-3xl font-extrabold text-slate-900 dark:text-white tracking-tight">Executive Dashboard</h2>
            <div className="px-3 py-1 bg-emerald-50 dark:bg-emerald-900/40 text-emerald-600 dark:text-emerald-400 text-[10px] font-black uppercase rounded-full border border-emerald-500/20 shadow-sm">
              REAL-TIME SYNC ACTIVE
            </div>
          </div>
          <p className="text-slate-500 dark:text-slate-400 font-medium italic">Comprehensive environmental impact monitoring for {currentUser.username}.</p>
        </div>
        <div className="flex gap-3">
          <button 
            onClick={() => setShowLogic(!showLogic)}
            className="px-5 py-2.5 rounded-xl font-bold border border-slate-200 dark:border-slate-800 text-slate-600 dark:text-slate-300 hover:bg-slate-100 dark:hover:bg-slate-800 transition-all flex items-center gap-2"
          >
            <i className="fa-solid fa-calculator"></i>
            {showLogic ? 'Hide Logic' : 'View Calculation Logic'}
          </button>
          <button onClick={handleExport} disabled={isExporting} className="bg-emerald-600 text-white px-5 py-2.5 rounded-xl font-bold shadow-lg shadow-emerald-500/20 hover:bg-emerald-500 transition-all disabled:opacity-50 flex items-center gap-2">
            {isExporting ? <i className="fa-solid fa-spinner animate-spin"></i> : <i className="fa-solid fa-download"></i>}
            Export CSV
          </button>
        </div>
      </header>

      {showLogic && (
        <div className="grid grid-cols-1 md:grid-cols-3 gap-6 animate-in slide-in-from-top duration-300">
           <div className="bg-emerald-50/50 dark:bg-emerald-900/20 border border-emerald-200/50 dark:border-emerald-500/20 p-5 rounded-2xl">
              <h4 className="text-xs font-black text-emerald-700 dark:text-emerald-400 uppercase tracking-widest mb-2">Carbon Equation</h4>
              <p className="text-xs leading-relaxed text-slate-600 dark:text-slate-400 font-medium">
                Calculated as: <code className="bg-emerald-100 dark:bg-emerald-900/40 px-1 rounded">Energy(kWh * Factor) + Material(Qty * Factor)</code>.
                Currently processing {energy.length} energy logs and {procurement.length} procurement records.
              </p>
           </div>
           <div className="bg-blue-50/50 dark:bg-blue-900/20 border border-blue-200/50 dark:border-blue-500/20 p-5 rounded-2xl">
              <h4 className="text-xs font-black text-blue-700 dark:text-blue-400 uppercase tracking-widest mb-2">Recyclability Weight</h4>
              <p className="text-xs leading-relaxed text-slate-600 dark:text-slate-400 font-medium">
                Uses a <strong>Weighted Average</strong> based on total quantity ({stats.totalQty} units). 
                High-volume purchases of non-recyclables will pull this KPI down faster.
              </p>
           </div>
           <div className="bg-amber-50/50 dark:bg-amber-900/20 border border-amber-200/50 dark:border-amber-500/20 p-5 rounded-2xl">
              <h4 className="text-xs font-black text-amber-700 dark:text-amber-400 uppercase tracking-widest mb-2">ESG Scoring</h4>
              <p className="text-xs leading-relaxed text-slate-600 dark:text-slate-400 font-medium">
                The mean average of <strong>Environmental, Social, and Governance</strong> scores provided for {suppliers.length} active suppliers in the Master Data.
              </p>
           </div>
        </div>
      )}

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
        <KPICard title="Gross Carbon Footprint" value={stats.totalCarbon.toLocaleString()} unit="kg CO2" icon="fa-cloud" color="rose" />
        <KPICard title="Supply Chain Health" value={stats.avgSupplierScore} unit="/ 100" icon="fa-award" color="emerald" />
        <KPICard title="Operational Spend" value={`$${stats.totalSpend.toLocaleString()}`} icon="fa-wallet" color="indigo" />
        <KPICard title="Circular Economy Rate" value={stats.avgRecyclability} unit="%" icon="fa-recycle" color="amber" />
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
        <div className="lg:col-span-2 bg-white dark:bg-slate-900 p-8 rounded-3xl border border-slate-200 dark:border-slate-800 shadow-sm dark:shadow-xl">
          <div className="flex justify-between items-center mb-8">
            <h3 className="text-lg font-bold text-slate-900 dark:text-white">CO2 Emission Trajectory</h3>
            <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Monthly Aggregation</span>
          </div>
          <div className="h-[300px]">
            <ResponsiveContainer width="100%" height="100%">
              <AreaChart data={trendData}>
                <CartesianGrid strokeDasharray="3 3" vertical={false} stroke={chartColors.grid} />
                <XAxis dataKey="month" axisLine={false} tickLine={false} tick={{fill: chartColors.text, fontSize: 11, fontWeight: 600}} />
                <YAxis axisLine={false} tickLine={false} tick={{fill: chartColors.text, fontSize: 11, fontWeight: 600}} />
                <Tooltip 
                  contentStyle={{ backgroundColor: chartColors.tooltipBg, borderRadius: '16px', border: `1px solid ${chartColors.tooltipBorder}`, boxShadow: '0 20px 25px -5px rgb(0 0 0 / 0.1)', color: theme === 'dark' ? '#fff' : '#000' }} 
                  itemStyle={{ color: '#10b981', fontWeight: 700 }}
                  formatter={(value) => [`${value} kg CO2`, 'Emissions']}
                />
                <Area type="monotone" dataKey="co2" stroke="#10b981" strokeWidth={4} fill="url(#colorEmerald)" fillOpacity={1} />
                <defs>
                  <linearGradient id="colorEmerald" x1="0" y1="0" x2="0" y2="1">
                    <stop offset="5%" stopColor="#10b981" stopOpacity={0.15}/>
                    <stop offset="95%" stopColor="#10b981" stopOpacity={0}/>
                  </linearGradient>
                </defs>
              </AreaChart>
            </ResponsiveContainer>
          </div>
        </div>

        <div className="bg-white dark:bg-slate-900 p-8 rounded-3xl border border-slate-200 dark:border-slate-800 shadow-sm dark:shadow-xl flex flex-col">
          <h3 className="text-lg font-bold mb-6 text-slate-900 dark:text-white text-center">Impact Attribution</h3>
          <div className="h-[250px] w-full relative">
            <ResponsiveContainer width="100%" height="100%">
              <PieChart>
                <Pie data={emissionBySourceData} cx="50%" cy="50%" innerRadius={70} outerRadius={95} paddingAngle={10} dataKey="value">
                  {emissionBySourceData.map((entry, index) => <Cell key={`cell-${index}`} fill={entry.color} stroke="none" />)}
                </Pie>
                <Tooltip 
                  contentStyle={{ backgroundColor: chartColors.tooltipBg, borderRadius: '16px', border: `1px solid ${chartColors.tooltipBorder}` }}
                  itemStyle={{ color: theme === 'dark' ? '#fff' : '#000', fontWeight: 700 }}
                />
              </PieChart>
            </ResponsiveContainer>
            <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 text-center pointer-events-none">
                <p className="text-[10px] text-slate-400 dark:text-slate-500 font-extrabold uppercase tracking-widest">Total CO2</p>
                <p className="text-2xl font-black text-slate-900 dark:text-white leading-none">{Math.round(stats.totalCarbon / 1000)}t</p>
            </div>
          </div>
          <div className="w-full space-y-3 mt-6">
             {emissionBySourceData.map(s => (
               <div key={s.name} className="flex justify-between items-center text-xs p-3 bg-slate-50 dark:bg-slate-800/50 rounded-xl border border-slate-100 dark:border-slate-800">
                 <div className="flex items-center gap-2">
                    <div className="w-2.5 h-2.5 rounded-full shadow-sm" style={{backgroundColor: s.color}}></div> 
                    <span className="text-slate-600 dark:text-slate-300 font-bold">{s.name}</span>
                 </div>
                 <span className="font-black text-slate-900 dark:text-white">{stats.totalCarbon > 0 ? Math.round((s.value / stats.totalCarbon) * 100) : 0}%</span>
               </div>
             ))}
          </div>
          <p className="text-[10px] text-center text-slate-400 dark:text-slate-500 font-medium mt-6">Calculated based on GHG Protocol standards.</p>
        </div>
      </div>
    </div>
  );
};

export default Dashboard;
